reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}


resource "aws_route53_zone" "primary" {
  name = "example53.com"
}

resource "aws_cloudwatch_log_group" "aws_route53_example_com" {
  name              = "/aws/route53/${aws_route53_zone.primary.name}"
  retention_in_days = 30
}

# Example CloudWatch log resource policy to allow Route53 to write logs
# to any log group under /aws/route53/*

data "aws_iam_policy_document" "route53-query-logging-policy" {
  statement {
    actions = [
      "logs:CreateLogStream",
      "logs:PutLogEvents",
    ]

    resources = ["arn:aws:logs:*:*:log-group:/aws/route53/*"]

    principals {
      identifiers = ["route53.amazonaws.com"]
      type        = "Service"
    }
  }
}

resource "aws_cloudwatch_log_resource_policy" "route53-query-logging-policy" {
  policy_document = data.aws_iam_policy_document.route53-query-logging-policy.json
  policy_name     = "route53-query-logging-policy"
}

resource "aws_route53_query_log" "example_com" {
  depends_on = [aws_cloudwatch_log_resource_policy.route53-query-logging-policy]

  cloudwatch_log_group_arn = aws_cloudwatch_log_group.aws_route53_example_com.arn
  zone_id                  = aws_route53_zone.primary.zone_id
}

response:
To accomplish the setup of Route 53 query logging with a CloudWatch Logs stream and a specific resource policy, you'll need to go through the following steps in Terraform:

1. **Create a CloudWatch Logs Log Group**: This will store the log events from Route 53 queries.
2. **Setup a Resource Policy for the Log Group**: This policy will allow Route 53 to send logs to the CloudWatch log group.
3. **Create a Route 53 Query Logging Config**: This will define what queries you want to log and specify the log group to send these queries to.

Below is the Terraform configuration covering each of the above steps in HCL format:

```hcl
resource "aws_cloudwatch_log_group" "route53_example" {
  name = "aws_route53_example_com"
}

resource "aws_cloudwatch_log_resource_policy" "route53_logging" {
  policy_name = "route53-query-logging-policy"
  policy_document = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Sid = "esQueryLogs"
        Effect = "Allow"
        Principal = {
          Service = "route53.amazonaws.com"
        }
        Action = "logs:PutLogEvents"
        Resource = "${aws_cloudwatch_log_group.route53_example.arn}:*"
        Condition = {
          ArnLike = {
            "aws:SourceArn": "arn:aws:route53:::*|*"
          }
        }
      }
    ]
  })
}

resource "aws_route53_query_log" "primary" {
  name      = "primary"
  hosted_zone_id = "ZXXXXXXXXXXXXX"  // Replace with the actual Hosted Zone ID
  cloudwatch_logs_cloudwatch_log_group_arn = aws_cloudwatch_log_group.route53_example.arn
}

# Ensure proper owner-based filtering in the Route 53 Query Log
resource "aws_route53_query_log_config" "primary_config" {
  cloudwatch_logs_config {
    cloudwatch_logs_log_group_arn = aws_cloudwatch_log_group.route53_example.arn
    filter = {}
  }

  hosted_zone_ids = [
    aws_route53_query_log.primary.hosted_zone_id
  ]
}
```

### Key Considerations:
- **CloudWatch Logs Resource Policy**: Ensure the policy allows Route 53 to send logs; this example assumes access from any Route 53 hosted zone.
- **Hosted Zone ID**: You will need to replace `ZXXXXXXXXXXXXX` with your actual Route 53 Hosted Zone ID.
- **Resource Policies**: These policies are critical for allowing permissions across your AWS resources, so ensure they align with your organization's security guidelines.

