response:
To set up weighted routing using AWS Route 53 resources to distribute traffic across three database instance replicas, we need to create a hosted zone and set up provider aliases corresponding to the different regions. The configuration involves managing the primary database instance and the respective replicas in different provider aliases. Here’s the step-by-step breakdown:

1. **Define Providers and Aliases:**
   - Create provider aliases `main`, `us-east`, `eu-central`, and `ap-southeast` for different AWS regions.

2. **Hosted Zone:**
   - Set up the hosted zone with Route 53 in `us-west-1`.

3. **Primary and Replica DB Instances:**
   - Define a primary database instance in `us-west-1`. 
   - Define three replicated database instances in `us-east-1`, `eu-central-1`, and `ap-southeast-1`.

4. **Configure Weighted DNS Records:**
   - Use Route 53 to create weighted DNS records that distribute traffic based on set weights to each of the replicated instances.

With these requirements in mind, here's how the Terraform configuration would look:

```hcl
provider "aws" {
  alias  = "main"
  region = "us-west-1"
}

provider "aws" {
  alias  = "us-east"
  region = "us-east-1"
}

provider "aws" {
  alias  = "eu-central"
  region = "eu-central-1"
}

provider "aws" {
  alias  = "ap-southeast"
  region = "ap-southeast-1"
}

resource "aws_route53_zone" "main" {
  provider = aws.main
  name    = "main"
}

resource "aws_route53_zone" "us-east" {
  provider  = aws.us-east
  name      = "primary"
}

resource "aws_route53_zone" "eu-central" {
  provider  = aws.eu-central
  name      = "primary"
}

resource "aws_route53_zone" "ap-southeast" {
  provider  = aws.ap-southeast
  name      = "primary"
}

resource "aws_rds_cluster" "primary" {
  provider = aws.main
  # Other configuration details for the primary RDS cluster
}

resource "aws_rds_cluster" "replica_us-east" {
  provider = aws.us-east
  # Other configurations for replica
  replica_identifier = "replica_us_east"
  # The replica settings have been omitted for brevity
}

resource "aws_rds_cluster" "replica_eu-central" {
  provider = aws.eu-central
  # Other configurations for replica
  replica_identifier = "replica_eu_central"
}

resource "aws_rds_cluster" "replica_ap-southeast" {
  provider = aws.ap-southeast
  # Other configurations for replica
  replica_identifier = "replica_ap_southeast"
}

resource "aws_route53_record" "weighted" {
  provider = aws.main
  zone_id   = aws_route53_zone.main.zone_id
  name      = "primary"
  type      = "CNAME"
  ttl       = "300"
  records = ["${aws_rds_cluster.replica.us-east.endpoint}"]

  weighted_routing_policy {
    weight = 100
  }
}

resource "aws_route53_record" "weighted_us-east" {
  zone_id  = aws_route53_zone.us-east.zone_id
  type      = "CNAME"
  name      = "primary"
  ttl       = "300"
  records   = ["${aws_rds_cluster.primary.main_us-east.endpoint}"]

  weighted_routing_policy {
    weight = 50
  }
}

resource "aws_route53_record" "weighted_eu-central" {
  zone_id   = aws_route53_zone.eu-central.zone_id
  type      = "CNAME"
  name      = "primary"
  ttl       = "300"
  records   = ["${aws_rds_cluster.replica_eu-central.endpoint}"]

  weighted_routing_policy {
    weight = 50
  }
}

resource "aws_route53_record" "weighted_ap-southeast" {
  zone_id   = aws_route53_zone.ap-southeast.zone_id
  type      = "CNAME"
  name      = "primary"
  ttl       = "300"
  records   = ["${aws_rds_cluster.replica_ap-southeast.endpoint}"]

  weighted_routing_policy {
    weight = 50
  }
}
```

This HCL code sets up the AWS Route 53 zone and RDS instances using provider aliases. It configures weighted routing policies by assigning weights to CNAME records pointing to RDS cluster endpoints, allowing traffic distribution across the database instances. For simplicity, configurations of the RDS cluster and precise record details are omitted and need further setup based on the actual instance specifications and requirements.

