response:
To set up a weighted DNS routing configuration using AWS Route 53, we need to create a hosted zone for the DNS management and then set up DNS records that distribute traffic between two read-replica database instances. Here’s the step-by-step process along with the Terraform configuration in HCL format:

1. **Hosted Zone Creation**: Define a hosted zone in Route 53 for domain management.

2. **DB Instances**: Define the Amazon RDS configuration for the primary instance and the read-replica instances.

3. **Weighted DNS Records**: Create Route 53 DNS A records with weights for distributing traffic between the read-replica instances.

Here is the Terraform configuration to achieve these requirements:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_route53_zone" "main_zone" {
  name = "main"
}

resource "aws_rds_cluster" "primary_cluster" {
  cluster_identifier = "primary-cluster"
  database_name     = "primary-db"
  db_instance_identifier = aws_db_instance.primary_db.id
  source_db_identifier = ""
}

resource "aws_db_instance" "primary_db" {
  identifier              = "primary"
  allocated_storage      = 20
  db_instance_class      = "db.t2.small"
  engine                = "mysql"
  engine_version        = "5.7"
  skip_final_snapshot   = true
  availability_zone     = "us-west-2a"
  db_name              = "primary-db"
  master_username      = "admin"
  master_password      = "yourpassword"
  storage_encrypted    = false
  db_subnet_group_name = aws_db_subnet_group.primary_group.name
}

resource "aws_rds_cluster_instance" "replica_cluster_instance_1" {
  identifier            = "replica-1-cluster"
  cluster_identifier    = aws_rds_cluster.primary_cluster.id
  instance_class        = "db.t2.small"
  db_subnet_group_name  = aws_db_subnet_group.primary_db_subnet_group.name
  availability_zone    = "us-west-2b"
  publicly_accessible  = true
}

resource "aws_rds_cluster_instance" "replica_cluster_instance_2" {
  identifier             = "replica-2-cluster"
  instance_class        = "db.t2.small"
  db_subnet_group_name = aws_db_subnet_group.main_db_subnet_group.name
  availability_zone    = "us-west-2c"
  publicly_accessible  = true
}

resource "aws_route53_record" "rds_primary_instance" {
  zone_id = aws_route53_zone.main_zone.zone_id
  name    = "primary"
  type    = "CNAME"
  ttl     = "60"
  records = ["primary-db-instance.c1.rds.amazonaws.com"]
}

resource "aws_route53_record" "rds_replica_instance_1" {
  zone_id = aws_route53_zone.main_zone.zone_id
  name = "replica1"
  type = "CNAME"
  ttl = "60"
  records = ["replica-1-db-instance.c1.rds.amazonaws.com"]
}

resource "aws_route53_record" "weighted_replica_1" {
  zone_id = aws_route53_zone.main_zone.zone_id
  name = "primary"
  type = "CNAME"
  ttl = "60"
  records = ["replica-cluster-1"]
  weighted_routing_policy {
    weight = 70
  }
}

resource "aws_route53_record" "weighted_replica_2" {
  zone_id = aws_route53_zone.main_zone.zone_id
  name = "primary"
  type = "CNAME"
  ttl = "60"
  records = ["replica-cluster-2"]
  weighted_routing_policy {
    weight = 30
  }
}

resource "aws_db_subnet_group" "primary_db_subnet_group" {
