Setting up an Elastic Beanstalk environment with Auto Scaling involves several steps. We need to create an IAM role and instance profile first, then set up the Elastic Beanstalk application and environment with Auto Scaling configurations based on CPU utilization. Below is the step-by-step Terraform configuration in HCL format:

1. **Create IAM Role and Instance Profile**: The IAM role will define the permissions for ECS tasks to interact with other AWS services. The instance profile is a container for an IAM role that allows AWS services to assume the role on behalf of an EC2 instance.

2. **Create Elastic Beanstalk Application**: This is where you define the application that you want to deploy.

3. **Create Elastic Beanstalk Environment**: This sets up the environment configuration, including Auto Scaling based on CPU utilization.

```hcl
provider "aws" {
  region = "us-west-2"
}

# IAM Role allowing Elastic Beanstalk to manage EC2 instances
resource "aws_iam_role" "eb_ec2_role" {
  name = "eb_ec2_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "ec2.amazonaws.com"
        }
      },
    ]
  })
}

# IAM Policy attachment for EC2 Elastic Beanstalk management
resource "aws_iam_role_policy_attachment" "eb_ec2_role_policy" {
  role       = aws_iam_role.eb_ec2_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSElasticBeanstalkWebTier"
}

# Instance profile linked to the IAM role
resource "aws_iam_instance_profile" "eb_ec2_profile" {
  name = "eb_ec2_profile"
  role = aws_iam_role.eb_ec2_role.name
}

# Elastic Beanstalk Application
resource "aws_elastic_beanstalk_application" "my_api_app" {
  name        = "my_api_app"
  description = "My API Application on Elastic Beanstalk"
}

# Elastic Beanstalk Environment with Auto Scaling Configuration
resource "aws_elastic_beanstalk_environment" "my_api_env" {
  name                = "my_api_env"
  application         = aws_elastic_beanstalk_application.my_api_app.name
  solution_stack_name = "64bit Amazon Linux 2 v3.3.6 running Node.js 14" # Example stack, adjust as needed

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MinSize"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:asg"
    name      = "MaxSize"
    value     = "4"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment"
    name      = "EnvironmentType"
    value     = "LoadBalanced"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "InstanceType"
    value     = "t2.micro"
  }

  setting {
    namespace = "aws:ec2:vpc"
    name      = "EC2KeyName"
    value     = "your-ec2-keypair-name"
  }

  setting {
    namespace = "aws:elasticbeanstalk:cloudwatch:logs"
    name      = "StreamLogs"
    value     = "true"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "MeasureName"
    value     = "CPUUtilization"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Statistic"
    value     = "Average"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "Unit"
    value     = "Percent"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperThreshold"
    value     = "75"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerThreshold"
    value     = "25"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "UpperBreachScaleIncrement"
    value     = "1"
  }

  setting {
    namespace = "aws:autoscaling:trigger"
    name      = "LowerBreachScaleIncrement"
    value     = "-1"
  }

  setting {
    namespace = "aws:elasticbeanstalk:environment:process:default"
    name      = "ServiceRole"
    value     = aws_iam_role.eb_ec2_role.arn
  }
}
```

Make sure to replace `"your-ec2-keypair-name"` with the name of an existing EC2 key pair for SSH access to the instances, and adjust the `solution_stack_name` to match your application stack needs. Additionally, consider any other custom settings required for your specific application deployment.

