resource "aws_elastic_beanstalk_environment" "batch_env" {
  name                = "BatchJobEnv"
  application         = aws_elastic_beanstalk_application.batch_job_app.name
  solution_stack      = "64bit Amazon Linux 2013.09 running Worker"
  tier               = "Worker"
  environment_name    = "${aws_elastic_beanstalk_environment_name_for_version}"
}

resource "aws_iam_role" "worker_role" {
  name = "worker_beanstalk_role"

  assume_role_policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Action": "sts:AssumeRole",
      "Principal": { "Service": "elasticbeanstalk.amazonaws.com" },
      "Effect": "Allow"
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "sqs_and_s3_access" {
  role       = aws_iam_role.worker_role.name
  policy_arn  = "arn:aws:iam::aws:policy/service-role/AWSElasticBeanstalkWorkerDeferredStorageAccessPolicy"

  policy = <<EOF
{
  "Version": "2012-10-17",
  "Statement": [
    {
      "Effect": "Allow",
      "Action": [
        "sqs:ReceiveMessage",
        "sqs:GetQueueUrl",
        "sqs:SendMessage",
        "s3:GetObject"
      ],
      "Resource": [ "${aws_sqs_queue.batch_job_queue.arn}", "${aws_s3_bucket.batch_bucket.arn}" ]
    }
  ]
}
EOF
}

resource "aws_iam_role_policy_attachment" "deferred_s3_access" {
  role       = aws_iam_role.worker_role.name
  policy_arn  = "arn:aws:iam::aws:policy/AmazonS3ReadOnlyAccess"
}

resource "aws_elastic_beanstalk_environment" "batch_env" {
  name        = "batch-job-env"
  tier        = "Worker"
  instance_profile = aws_iam_instance_profile.eb_ec2_profile.arn
  solution_stack_name = "64bit Amazon Linux 2013.09 running Worker"
  application_version = aws_elastic_beanstalk_application_version.app_version.arn

  settings = {
    tier_settings = {
      "name"         = "WorkerTier",
      "environment" = "${aws_iam_role.eb_ec2_role.arn}"
    }
  }

  lifecycle {
    create_before_destroy = true
  }
}
```

Ensure that the configurations match actual policy details and resources, and replace placeholder values with specific ARNs and policy content according to your account data.

