# RDS for Production environment
resource "aws_db_instance" "prod_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t2.micro"
  name                 = "prod_db"
  username             = "prod_user"
  password             = "YourSecurePassword123!"
  parameter_group_name = "default.mysql8.0"
  skip_final_snapshot  = true
  publicly_accessible  = true
}

# IAM Policy for RDS access for Production
resource "aws_iam_role_policy" "prod_rds_policy" {
  role   = aws_iam_role.eb_role.name
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "rds-db:connect"
        ],
        Effect = "Allow",
        Resource = "arn:aws:rds-db:${var.region}:${data.aws_caller_identity.current.account_id}:dbuser:${aws_db_instance.prod_db.identifier}/prod_user"
      }
    ]
  })
}

# Elastic Beanstalk Application and Environment for Production
