To set up a blue-green deployment using AWS Elastic Beanstalk with an RDS database and the specified instance profile, we'll follow these steps using Terraform. The steps include creating an RDS database, requesting a database snapshot, setting up two Elastic Beanstalk environments, and configuring the EC2 instance profile. Here is the HCL code that accomplishes this setup:

```hcl
provider "aws" {
  region = "us-east-1" # Change this to your AWS region
}

# Define variables
variable "db_snapshot_identifier" {
  description = "The identifier for the RDS database snapshot"
  default     = "my-db-snapshot"
}

resource "aws_db_instance" "default" {
  identifier = "my-db"
  allocated_storage         = 20
  engine                    = "mysql"
  engine_version            = "5.7"
  instance_class            = "db.t2.micro"
  name                     = "my-db"
  username                 = "dbadmin"
  password                 = "password" # Replace with your passwords management
  parameter_group_name      = "default.mysql5.7"
  db_subnet_group_name      = "my-db-subnet-group"
  vpc_security_group_ids    = [aws_security_group.my_db_sg.id]
  tags = {
    Name = "MyDBInstance"
  }
}

resource "aws_db_snapshot" "default_snapshot" {
  db_instance_id = aws_db_instance.default.id
  db_snapshot_identifier = var.db_snapshot_identifier
}

# Elastic Beanstalk application resources
resource "aws_s3_bucket" "elasticbeanstalk_bucket" {
  bucket = "my-app-${var.db_snapshot_identifier}"
  acl    = "private"
}

resource "aws_elastic_beanstalk_application" "app" {
  name          = "my-app"
  description   = "My application"
}

resource "aws_elastic_beanstalk_environment" "blue_env" {
  name                = "my-app-blue"
  application         = aws_elastic_beanstalk_application.app.id
  solution_stack     = "64bit Amazon Linux 2016.03 v10.2.1 running PHP 7.0"
  tier_type          = "WebServer"
  tier_name          = "admin"
  environment_name   = "MyApplicationEnvironment"
  environment_id     = "bbev2xABC123"
  settings          = {
    TierName         = "admin"
    DatabaseURL      = "RDS_DB_URI"
    DBName          = aws_db_instance.default.name
    S3BucketName    = aws_s3_bucket.elasticbeanstalk_bucket.bucket
    InstanceType    = "t2.micro"
    EBDownloasURL  = "https://s3.amazonaws.com/my-bucket/app.zip"
  }
  instance_profile = "arn:aws:iam::123456789012:instance-profile/ec2_eb_profile1"
}

resource "aws_elastic_beanstalk_environment" "green_env" {
  name                = "my-app-green"
  application         = aws_elastic_beanstalk_application.app.id
  solution_stack     = "64bit Amazon Linux 2016.03 v10.4.0 running Node.js"
  tier_type          = "WebServer"
  instance_profile = "arn:aws:iam::123456789012:instance-profile/ec2_eb_profile1"
  settings = {
    TierName         = "WebServer"
    DatabaseURL      = "RDS_DB_URI"
    DBName          = aws_db_instance.default.name
    S3BucketName    = aws_s3_bucket.elasticbeanstalk_bucket.bucket
  }
}

resource "aws_elastic_beanstalk_application_version" "blue_env_version" {
  application     = aws_elastic_beanstalk_application.app.name
  bucket         = aws_s3_bucket.elasticbeanstalk_bucket.id
  key           = "blue.zip"
}

resource "aws_elastic_beanstalk_application_version" "green_env_version" {
  application   = aws_elastic_beanstalk_application.app.name
  bucket       = aws_s3_bucket.elasticbeanstalk_bucket.id
  key         = "green.zip"
}

# Security group for RDS
resource "aws_security_group" "my_db_sg" {
  name        = "my-db-sg"
  description = "Security group for my RDS instance"
  vpc_id     = aws_vpc.default.id
}

resource "aws_security_group_rule" "rds_sg_rule" {
  type = "ingress"
  from_port = 3306
  to_port = 3306
  protocol = "tcp"
  cidr_blocks = ["0.0.0.0/0"]
  security_group_id = aws_security_group.my_db_sg.id
}
```

**Notes:**
- Ensure the `RDS_DB_URI` is set up according to your RDS configuration.
- Replace the placeholder values like `123456789012` with your actual AWS Account ID and other placeholders like password management with safer options.
- Ensure that the environments use different solution stacks for a blue-green deployment and have the appropriate identification settings. 

This configuration sets up both the blue and green environments in Elastic Beanstalk, with the instance profile and snapshot management as requested.

