    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_us_east.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# RDS in EU West (Ireland)
resource "aws_db_instance" "main_db_eu_west" {
  provider             = aws.eu_west_1
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "5.7"
  instance_class       = "db.t3.micro"
  multi_az             = true
  username             = "dbadmin"
  password             = "mysecurepassword"
  parameter_group_name = "default.mysql5.7"
  skip_final_snapshot  = true
}

# Elastic Beanstalk Application in EU West
resource "aws_elastic_beanstalk_application" "myapp_eu_west" {
  provider = aws.eu_west_1
  name     = "my-application-eu-west"
}

# Elastic Beanstalk Environment in EU West
resource "aws_elastic_beanstalk_environment" "myenv_eu_west" {
  provider            = aws.eu_west_1
  name                = "my-application-env-eu-west"
  application         = aws_elastic_beanstalk_application.myapp_eu_west.name
  solution_stack_name = "64bit Amazon Linux 2023 v4.3.0 running Python 3.9"

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_HOST"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_USERNAME"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:elasticbeanstalk:application:environment"
    name      = "DB_PASSWORD"
    value     = aws_db_instance.main_db_eu_west.address
  }

  setting {
    namespace = "aws:autoscaling:launchconfiguration"
    name      = "IamInstanceProfile"
    value     = aws_iam_instance_profile.eb_ec2_profile.name
  }
}

# Main Route 53 Hosted Zone
resource "aws_route53_zone" "main" {
  provider = aws.us_east_1
  name = "myapp.com"
}

# Latency Based Routing in Route 53 for US East Elastic Beanstalk Environment
resource "aws_route53_record" "eb_env_us_east" {
  provider = aws.us_east_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "us-east.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_us_east.cname]
  set_identifier = "EastEnv"
  latency_routing_policy {
    region = "us-east-1"
  }
}

resource "aws_route53_record" "eb_env_eu_west" {
  provider = aws.eu_west_1
  zone_id = aws_route53_zone.main.zone_id
  name    = "eu-west.myapp.com"
  type    = "CNAME"
  ttl     = "60"
  records = [aws_elastic_beanstalk_environment.myenv_eu_west.cname]
  set_identifier = "WestEnv"
  latency_routing_policy {
    region = "eu-west-1"
  }
}

response:
To set up a multi-region app deployment using Route 53 to host a domain and route requests to Elastic Beanstalk environments backed by attached RDS databases across AWS regions, we need to systematically approach the requirements:

1. **Elastic Beanstalk Application Setup**: 
   - Create two applications in `us-east-1` and `eu-west-1` zones. These should be specifically named and ensure they are deployed in the respective regions.
   - Set up Elastic Beanstalk environments to serve as deployment containers for the app, named `myenv_us_east` and `myenv_eu_west`.

2. **Amazon RDS Databases**: 
   - Set up relational databases in both regions named `main_db_us_east` and `main_db_eu_west`, ensuring they have connectivity to the respective Elastic Beanstalk environments.

3. **Route 53 Configuration**: 
   - Utilize Route 53 for domain hosting and request routing by setting up records for domain pointers to each region's Elastic Beanstalk environment.
   - Implement a DNS routing policy that redirects requests based on the specified region.
   - Map domain requests to the respective environments using DNS aliases "us-east-1" and "eu-west-1."

4. **IAM Roles**: 
   - Ensure AWS IAM roles are configured with appropriate permissions for the Elastic Beanstalk environments and RDS instances via the instance profile "eb_ec2_profile3."

5. **VPC & Subnets**: 
   - Attach and configure VPCs and appropriate subnets for regions supporting the necessary connectivity for Elastic Beanstalk and RDS.

