terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_lex_intent" "order_flowers" {
  name = "OrderFlowers"
  description = "Intent to order a bouquet of flowers for pick up"

  sample_utterances = [
    "I would like to pick up flowers",
    "I would like to order some flowers",
  ]

  slot {
    name                     = "FlowerType"
    description              = "Type of flower to order"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.AlphaNumeric"
    priority                 = 1

    sample_utterances = ["I would like to get {FlowerType} flower."]

    value_elicitation_prompt {
      message {
        content             = "What type of flower would you like?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  slot {
    name                     = "PickupDate"
    description              = "Date of flower pickup"
    slot_constraint          = "Required" 
    slot_type                = "AMAZON.DATE"
    priority                 = 2

    value_elicitation_prompt {
      message {
        content             = "When would you like to pickup your flower?"
        content_type        = "PlainText"
      }
      max_attempts         = 2
    }
  }

  confirmation_prompt {
    max_attempts = 2

    message {
      content      = "Okay, your {FlowerType} will be ready for pickup on {PickupDate}.  Does this sound okay?"
      content_type = "PlainText"
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }

  rejection_statement {
    message {
      content      = "Okay, I will not place your order."
      content_type = "PlainText"
    }
  }
}

resource "aws_lex_bot" "order_flowers" {
  name     = "OrderFlowers"
  description = "Bot to order flowers on the behalf of a user"
  locale   = "en-US"
  process_behavior = "BUILD"
  voice_id = "Salli"
  child_directed = false
  create_version = false
  detect_sentiment            = false
  idle_session_ttl_in_seconds = 600

  abort_statement {
    message {
      content_type = "PlainText"
      content      = "Sorry, I am not able to assist at this time"
    }
  }

  clarification_prompt {
    max_attempts = 2

    message {
      content_type = "PlainText"
      content      = "I didn't understand you, what would you like to do?"
    }
  }

  intent {
    intent_name    = aws_lex_intent.order_flowers.name
    intent_version = aws_lex_intent.order_flowers.version
  }
}

response:
To build an AWS Lex chatbot using Terraform, we'll need to consider the following components: 

- AWS Lex bot resource
- Bot aliases
- Intents and slots
- Permission settings
- Roles for Lex execution

Here's a step-by-step approach to building a simple AWS Lex bot:

1. **Create the AWS Lex Bot**: Define the Lex bot with basic configuration.
2. **Define Intents**: Create a basic intent for the bot (e.g., a "HelloWorld" intent).
3. **Setup Slots**: Define slots if necessary for the intent.
4. **Create Alias**: Set up an alias to point to a specific version of the bot.
5. **Configure Roles**: Set up IAM roles for Lex execution and usage.

Below is the Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_iam_role" "lex_bot_role" {
  name = "LexBotRole"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "lex.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "lex_bot_policy_attachment" {
  role       = aws_iam_role.lex_bot_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lex_bots" "example_lex_bot" {
  name          = "ExampleLexBot"
  role_arn      = aws_iam_role.lex_bot_role.arn
  log_bot casual = true
  log_user casual = true

  bot_mode = "PRODUCTION"

  idle_session_ttl_in_seconds = 300
}

resource "aws_lex_bot_intent" "hello_world_intent" {
  bot_name   = aws_lex_bots.example_lex_bot.name
  intent_name = "HelloWorld"
  fulfillment_activity {
    type = "ReturnIntent"
  }

  sample_utterances = [
    "Hello",
    "Hi",
  ]
}

resource "aws_lex_bot_alias" "example_lex_bot_alias" {
  name       = "ExampleAlias"
  bot_name   = aws_lex_bots.example_lex_bot.name
  bot_version = "$LATEST"
}
```

This configuration sets up a basic AWS Lex bot with a simple intent. Adjust the configuration as needed for additional intents, slots, and more complex interactions.

