}


resource "aws_lex_bot" "pizza_order_bot" {
  name = "PizzaOrderBot"
  description = "Pizza order bot"
  idle_session_ttl_in_seconds = 600
  create_version = false
  child_directed = false

  abort_statement {
    message {
      content = "Sorry, I am not able to assist."
      content_type = "PlainText"
    }
  }

  clarification_prompt {
    max_attempts = 2
    message {
      content = "I'm sorry, I didn't understand that. Can you try again?"
      content_type = "PlainText"
    }
  }

  intent {
    intent_name = aws_lex_intent.OrderPizzaIntent.name
    intent_version = aws_lex_intent.OrderPizzaIntent.version
  }
}

resource "aws_lex_intent" "OrderPizzaIntent" {
  name = "OrderPizzaIntent"
  create_version = true

  sample_utterances = [
    "I would like to pick up a pizza",
    "I would like to order some pizzas",
  ]

  slot {
    name = "PizzaType"
    description = "Type of pizza to order"
    priority = 1  # must be in [1, 100]
    slot_type = aws_lex_slot_type.PizzaType.name
    slot_type_version = aws_lex_slot_type.PizzaType.version
    slot_constraint = "Required"

    sample_utterances = ["I want a {PizzaType} pizza.", "A {PizzaType} pizza please."]

    value_elicitation_prompt {
      max_attempts = 2
      message {
        content = "What type of pizza would you like to order?"
        content_type = "PlainText"
      }
    }
  }

  confirmation_prompt {
    max_attempts = 2
    message {
      content = "So, you would like to order a pizza. Is that correct?"
      content_type = "PlainText"
    }
  }

  rejection_statement {
    message {
        content = "Sorry, I don't know how to help then"
        content_type = "PlainText"
      }
    }

  follow_up_prompt {
    prompt {
      max_attempts = 2
      message {
        content = "Would you like anything else with your order?"
        content_type = "PlainText"
      }
    }
    rejection_statement {
      message {
        content = "OK, Your pizza is on its way."
        content_type = "PlainText"
      }
    }
  }

  fulfillment_activity {
    type = "ReturnIntent"
  }
}

resource "aws_lex_slot_type" "PizzaType" {
  create_version = true
  description = "Types of pizza available to order"
  name = "PizzaTypes"
  enumeration_value {
    value = "Margherita"
  }
  enumeration_value {
    value = "Pepperoni"
  }
}

response:
To build an AWS Lex bot for pizza ordering with Terraform, we'll need to follow several steps: create a bot, define intents, slots, sample utterances, and follow-up prompts. Here’s how we can achieve this:

1. **Create the Lex Bot**: Define the bot, including user and bot languages and a time-to-live (TTL) for the bot session.

2. **Define Intents**: We will need at least one intent, such as `PizzaOrderIntent`, for ordering pizzas. This will include input slots for various order details.

3. **Define Slots**: For the `PizzaOrderIntent`, slots will include `PizzaSize`, `Toppings`, and `Quantity`.

4. **Sample Utterances**: Provide sample phrases a user might say when ordering a pizza.

5. **Set Follow-up Prompt**: Determine follow-up questions if the bot needs more information.

Here's the complete Terraform configuration for the above in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_lex_bot" "pizza_lex_bot" {
  name                      = "PizzaOrderBot"
  checksum                 = ""
  clarification_prompt      = {
    messages = [
      {
        contentType = "PlainText"
        content     = "I'm sorry. I didn't understand that. Can you please specify the pizza size, toppings, and quantity?"
      }
    ]
    max_attempts = 5
  }
  abort_statement = {
    messages = [
      {
        contentType = "PlainText"
        content     = "Sorry, I could not understand. Please try again."
      }
    ]
  }
  process_behavior = "Build"
  idle_session_ttl_in_seconds = 300
  voice_settings = {
    voice_id = "Joanna"
    output_speech_speech_markup = "SSML"
  }
  locale = "en-US"
  child_directed = false
  failure_reasons = []
}

resource "aws_lex_intent" "pizza_order_intent" {
  name            = "PizzaOrderIntent"
  checksum        = ""
  fulfillment_activity {
    type = "ReturnIntent"
  }
  prompt {
    max_retries          = 2
    messages = [
      {
        contentType = "PlainText"
        content     = "What size of pizza would you like? (Small, Medium, Large)"
      }
    ]
    verbose_disabled = false
  }
  slots = [
    aws_lex_slot.pizza_size.id,
    aws_lex_slot.toppings.id,
    aws_lex_slot.quantity.id,
  ]
  confirmation_prompt {
    max_attempts = 2
    messages = [
      {
        contentType = "PlainText"
        content     = "You ordered a {PizzaSize} pizza with {Toppings}, quantity {Quantity}. Is this correct?"
      }
    ]
  }
  rejection_statement {
    messages = [
      {
        contentType = "PlainText"
        content     = "Order cancelled."
      }
    ]
  }
}

resource "aws_lex_slot" "pizza_size" {
  name                       = "PizzaSize"
  slot_type                  = "AMAZON.PHONE_NUMBER"
  description                = "Size of the pizza"
  prompt {
    max_retries              = 3
    messages                 = [
      {
        contentType = "PlainText"
        content     = "Please provide the pizza size like Small, Medium, or Large."
      }
    ]
  }
  confirmation_prompt {
    max_attempts = 2
    messages = [
      {
        contentType = "PlainText"
        content     = "You've selected {PizzaSize} size, is that correct?"
      }
    ]
  }
  value_elicitation_prompt {
    max_retries            = 2
    messages               = [
      {
        contentType = "PlainText"
        content     = "Please tell me the size of the pizza."
      }
    ]
  }
  priority               = 1
  sample_utterances      = [
    "I want a {PizzaSize} pizza",
    "Order a {PizzaSize} one",
  ]
}

resource "aws_lex_slot" "toppings" {
  name                       = "Toppings"
  slot_type                  = "AMAZON.GLOBAL_DIALOG_STATE"
  description                = "Toppings to be included on the pizza"
  prompt {
    max_retries              = 3
    messages                 = [
      {
        contentType = "PlainText"
        content     = "What toppings would you like on your pizza?"
      }
    ]
  }
  confirmation_prompt {
    max_attempts = 2
    messages = [
      {
        contentType = "PlainText"
        content     = "You've selected {Toppings} as toppings, is that correct?"
      }
    ]
  }
  value_elicitation_prompt {
    max_retries            = 2
    messages               = [
      {
        contentType = "PlainText"
        content     = "Please specify the toppings you would like."
      }
    ]
  }
  priority               = 2
  sample_utterances      = [
    "I want my pizza with {Toppings}",
    "Add {Toppings} to the pizza",
  ]
}

resource "aws_lex_slot" "quantity" {
  name                       = "Quantity"
  slot_type                  = "AMAZON.NUMBER"
  description                = "Number of pizzas"
  prompt {
    max_retries              = 3
    messages                 = [
      {
        contentType = "PlainText"
        content     = "How many pizzas would you like?"
      }
    ]
  }
  confirmation_prompt {
    max_attempts = 2
    messages = [
      {
        contentType = "PlainText"
        content     = "You want {Quantity} pizza(s), is that correct?"
      }
    ]
  }
  value_elicitation_prompt {
    max_retries            = 2
    messages               = [
      {
        contentType = "PlainText"
        content     = "Please tell me how many pizzas you want."
      }
    ]
  }
  priority               = 3
  sample_utterances      = [
    "I need {Quantity} pizzas",
    "Order {Quantity} of them",
  ]
}
```

