provider "aws" {
  region = "us-east-1" # Set your region
}

# Lambda Function for Pizza Ordering
resource "aws_lambda_function" "pizza_ordering_function" {
  function_name = "pizzaOrderingFunction"
  filename      = "pizzaOrderingFunction.zip"
  handler      = "index.handler"
  role        = aws_iam_role.lex_lambda_role.arn
  runtime     = "nodejs14.x"
}

# IAM Role for Lambda
resource "aws_iam_role" "lex_lambda_role" {
  name = "lexLambdaRole"
  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

# AWS Lex Bot for Pizza Ordering
resource "aws_lex_bot" "pizza_order_bot" {
  name  = "PizzaOrderingBot"
  description = "A bot that handles pizza orders"

  # Slots, intros, and fulfillment
  amazon_lex_slot {
    name     = "PizzaType"
    bucket   = "s3"
    value   = {
      type   = "S3"
      s3_bucket_name = "my-lex-slots-bucket"
      key = "PizzaType"
    }

    sample_utterance = "I would like a Margherita"
    validation_requirement {
      validation_type       = "None"
    }
  }

  amazon_lex_slot {
    name     = "PizzaSize"
    bucket   = "s3"
    value   = {
      type   = "S3"
      s3_bucket_name = "my-lex-slots-bucket"
      key = "SizeModifier"
    }

    sample_utterance = "I want a large pizza"
    validation_requirement {
      validation_type = "None"
    }
  }

  amazon_lex_conversation {
    name       = "PizzaOrderingConversation"
    overview  = {
      intents = [
        {
          intent = "OrderPizza"
          slots = [
             {
              name = "PizzaType"
              slot_type = "AMAZON.S3"
            },
            {
              name = "PizzaSize"
              slot_type = "AMAZON.S3"
            }
          ]
         }
    }
    fulfillment_type = "AWS Lambda"
    version = "Custom"
    request_slot_time_limit = "12000"
    auto_branching = true
  }
}

# Lex bot Alias
resource "aws_lex_bot_alias" "pizza_ordering_alias" {
  bot_id               = aws_lex_bot.pizza_order_bot.id
  bot_version = "Live bot"
  name = "PizzaOrderingProductionBot"
  description = "Production version of the pizza ordering bot."

