        }
      }
    }
  ]

  clarification_prompt = {
    clarification_prompt_key="PizzaClarifyIntent"
    messages[0] = "I'm sorry, I didn't understand that. Can you rephrase?"
  }

  closing_statement   = {
    closing_statement_key = "PizzaClosing"
    messages[0] = "Thank you for ordering your pizza!"
  }
}

