      slot_constraint        = "Required"
      prompt = {
        messages = [
          {
            content = "What topping would you like on your pizza?"
          }
        ]
      }
    },
    {
      name           = "Size"
      description    = "Size of the pizza"
      slot_type      = aws_lex_slot_type.size_slot_type_link.arn
      slot_constraint = "Required"
      prompt = {
        messages = [
          {
            content = "What size would you like your pizza?"
          }
        ]
      }
    }
  ]

  fulfillment = {
    type = "ReturnIntent"
  }
}

resource "aws_lex_bot" "children_pizza_bot" {
  name           = "ChildrenPizzaOrderBot"
  description    = "A Lex bot for children to place a pizza order"
  role_arn       = aws_iam_role.lex_role.arn
  idle_session_ttl_in_seconds = 300
  locale         = "en-US"

  child_directed = true

  checkpoint_linked_intents = [
    aws_lex_intent.input_slot_types.id
  ]

  intents = [
    aws_lex_intent.children_pizza_order.id
  ]

  intents_version = "NEW"
}

```

### Key Considerations:
- **IAM Role**: The role allows AWS Lex to perform actions within AWS.
- **Child-Directed**: To ensure compliance for content designed explicitly for children, `child_directed` is set to `true`.
- **Intents and Slots**: Define required slots for 'Topping' and 'Size' with sample utterances for interaction.
- **Locale**: While the bot currently supports English (en-US), you can extend support to other languages as needed.

