To create an AWS Connect bot association tailored for children, we must first set up the necessary resources for AWS Connect. We'll need to create an IAM role for the Lambda function that will be used by the bot and then configure the AWS Connect Bot to associate with a Lambda function.

Steps:
1. Create an IAM role and policy for the Lambda function.
2. Create a Lambda function for the bot logic.
3. Create a class for the bot (e.g., "Kids Chat Bot").
4. Create a Lex bot integrated with Lex bot integration.
5. Create an AWS Connect instance.
6. Create an AWS Connect bot associate and instance bot.
7. Associate the bot with the AWS Connect instance.

Here is the Terraform HCL configuration for the above steps:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "bot_lambda_role" {
  name = "connect-bot-lambda-role"

  assume_role_policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [
      {
        Action    = "sts:AssumeRole",
        Effect    = "Allow",
        Principal = {
          Service = "lambda.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "bot_lambda_policy" {
  name = "connect-bot-lambda-policy"
  role = aws_iam_role.bot_lambda_role.id

  policy = jsonencode({
    Version   = "2012-10-17",
    Statement = [
      {
        Action   = [
          "connect:GetInstance",
          "connect:GetDetails",
          "lex:PostText"
        ],
        Effect   = "Allow",
        Resource = "*"
      },
    ]
  })
}

resource "aws_lambda_function" "bot_lambda" {
  function_name = "connect-kids-bot"
  role          = aws_iam_role.bot_lambda_role.arn

  # This would normally point to your Lambda code ZIP file
  filename      = "lambda_function_payload.zip"

  handler       = "index.handler"
  runtime       = "nodejs14.x"

  # environment variable for bot name
  environment {
    variables = {
      bot_name = "KidsChatBot"
    }
  }
}

resource "aws_lex_bot" "kids_lex_bot" {
  name                      = "KidsChatBot"
  role_arn                  = aws_iam_role.bot_lambda_role.arn
  checksum                  = filebase64sha256("lex-bot-definition.json")
  locale                    = "en_US"
  child_directed            = true

  # The JSON payload for definition, typically loaded from file
  intents {
    name                 = "KidsGreetingIntent"
    fulfillment_activity {
      type               = "CodeHook"
      code_hook {
        uri = aws_lambda_function.bot_lambda.arn
        message_version = "1.0"
      }
    }
  }

  # additional configurations...
}

resource "aws_connect_instance" "connect_instance" {
  identity_management_type = "CONNECT_MANAGED"
  instance_alias           = "ChildrenConnectInstance"
  directory_id             = "d-90273a73"  # Example Directory ID, replace with actual
}

resource "aws_connect_bot" "kids_bot" {
  name                      = "KidsBot"
  instance_id               = aws_connect_instance.connect_instance.id
  description               = "A bot tailored for children interactions."
  timeout_seconds           = 300

  # Bot attributes and configurations...
}

resource "aws_connect_instance_bot_association" "kids_bot_association" {
  instance_id      = aws_connect_instance.connect_instance.id
  target_identifier = aws_connect_bot.kids_bot.id
}
```

**Notes:**
- Ensure to replace placeholders like `"lambda_function_payload.zip"` and `"lex-bot-definition.json"` with actual file paths or content.
- The directory ID is an example. Update it with the actual directory ID where AWS Connect is integrated.
- Further bot configuration details (e.g., intents, attributes) should match your specific requirements for the children-targeted bot.

