Certainly! To fulfill this request, we'll need to define several resources in our Terraform configuration:

1. **S3 Bucket**: This will be the source where Kinesis Data Firehose will fetch the data.
2. **IAM Role and Policies**: An IAM role is needed for the Firehose delivery stream to allow it to interact with AWS services like S3 and Elasticsearch.
3. **Kinesis Data Firehose Delivery Stream**: The stream itself will manage the data flow from the S3 bucket to the Elasticsearch domain.

Here's the full Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

# Create an S3 bucket for Firehose input
resource "aws_s3_bucket" "input_bucket" {
  bucket = "firehose-input-bucket"
  acl    = "private"
}

# Create an IAM role for Firehose
resource "aws_iam_role" "firehose_role" {
  name = "firehose_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = "sts:AssumeRole",
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

# Attach policy to the IAM role for S3 access
resource "aws_iam_policy" "s3_access_policy" {
  name        = "s3_access_policy"
  path        = "/"
  description = "Allow access to S3 bucket from Firehose"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Action = [
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket"
        ],
        Effect = "Allow",
        Resource = [
          aws_s3_bucket.input_bucket.arn,
          "${aws_s3_bucket.input_bucket.arn}/*"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach_s3_policy" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.s3_access_policy.arn
}

# Create an IAM policy for Firehose to send data to Elasticsearch
resource "aws_iam_policy" "elasticsearch_policy" {
  name        = "elasticsearch_access_policy"
  path        = "/"
  description = "Allow Firehose to send data to Elasticsearch"

  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect   = "Allow",
        Action   = "es:ESHttpPut",
        Resource = "arn:aws:es:us-west-2:123456789012:domain/my-elasticsearch-domain/*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach_es_policy" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.elasticsearch_policy.arn
}

# Kinesis Data Firehose delivery stream
resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "firehose-es-destination"

  delivery_stream_type = "DirectPut"

  aws_iam_role_arn = aws_iam_role.firehose_role.arn

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.input_bucket.arn

    buffering_config {
      interval           = 60
      size               = 128
      destination_id     = "s3"
    }
  }

  elasticsearch_configuration {
    domain_arn     = "arn:aws:es:us-west-2:123456789012:domain/my-elasticsearch-domain"
    index_name     = "my-index"
    role_arn       = aws_iam_role.firehose_role.arn

    buffer_size = 5
    buffer_interval = 300

    retry_options {
      duration = 300
    }

    document_id_format = "_CI_TIMESTAMP"
    codec              = "PLAIN_TEXT"
  }
}
```

### Explanation:

- **S3 Bucket**: The `aws_s3_bucket` resource creates the input S3 bucket for Firehose to consume data.

- **IAM Role**: The `aws_iam_role` resource establishes an IAM role that Firehose can assume.

- **IAM Policies**: Two policies are created to grant necessary permissions:
  - `aws_iam_policy.s3_access_policy` allows Firehose to read from the S3 bucket.
  - `aws_iam_policy.elasticsearch_policy` permits sending data to the Elasticsearch domain.

- **Kinesis Data Firehose Delivery Stream**: The `aws_kinesis_firehose_delivery_stream` resource sets up the Firehose stream with configurations for both S3 as a source and Elasticsearch as a destination.

- **Assumed Values**: Be sure to replace placeholders (such as the ARN of Elasticsearch and user-specific ARN in the policies) with actual values from your AWS environment.

