  acl    = "private"
}

data "aws_iam_policy_document" "firehose_role_policy" {
  statement {
    actions = [
      "s3:GetBucketLocation",
      "s3:PutObject",
    ]
    resources = [
      aws_s3_bucket.firehose_bucket.arn,
    ]
  }

  statement {
    actions = [
      "firehose:DescribeDeliveryStream",
      "firehose:PutRecord",
      "firehose:PutRecordBatch",
      "firehose:ListDeliveryStreams",
      "firehose:CreateDeliveryStream",
      "firehose:DeleteDeliveryStream",
      "firehose:UpdateDeliveryStream",
    ]
    resources = ["*"]
  }

  statement {
    actions = [
      "logs:PutLogEvents",
      "logs:CreateLogStream",
    ]
    resources = ["arn:aws:logs:us-west-2:*:*"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name   = "firehose_policy"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose_role_policy.json
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name        = "my-firehose-stream"
  destination = "extended_s3"

  extended_s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.firehose_bucket.arn
    buffer_size        = 10
    buffer_interval    = 300
    compression_format = "UNCOMPRESSED"
  }

  delivery_stream_instance_configuration {
    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.firehose_bucket.arn
    }
  }

  destination_configuration {
    splunk_configuration {
      processing_configuration {
        enabled = "true"

        processor {
          type  = "Lambda"
          parameters = [
            {
              ParameterName  = "LambdaArn"
              ParameterValue = "arn:aws:lambda:us-west-2:123456789012:function:my-lambda-function"
            },
          ]
        }
      }

      s3_backup_configuration {
        role_arn   = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.firehose_bucket.arn
        buffer_size        = 10
        buffer_interval    = 300
      }

      http_endpoint_configuration {
        endpoint_name = "my-splunk-endpoint"
        endpoint_url  = "https://my-splunk-enforce.trust.aws"
        buffer_size        = 10
        buffer_interval    = 300
        cloudwatch_logging_options {
          enabled = true
          log_group_name = "my-splunk-log-group"
          log_stream_name = "my-splunk-log-stream"
        }

        request_configuration {
          content_type = "application/json"

          request_header_configuration {
            http_header {
              header_name = "Authorization"
              header_value = "Bearer mySplunkAuthToken"
            }
          }
        }
      }
    }
  }
}
```

### Notes:
- Replace `"my-firehose-bucket"`, `"my-lambda-function"`, and `"my-splunk-auth-token"` with real names/IDs of your resources and security token.
- Update AWS region, S3 bucket ARNs, and Splunk endpoint URL according to your setup.
- Ensure you have the required permissions to execute these actions and that the AWS account has Kinesis Data Firehose access permissions.
- Make sure the Splunk endpoint URL and Bearer token are securely stored and accessed from a secure source, such as environment variables or a secrets manager.

