    security_group_ids = [aws_default_elasticsearch_sg.id] # adjust security group as necessary
    vpc_id            = var.vpc_id
  }
  access_policies = jsonencode([{
    version = "2012-10-17"
    statement = [{
      effect = "Allow"
      actions = ["es:ESHttpPost", "es:ESHttpPut", "es:ESHttpGet"]
      principals = [{
        type = "AWS"
        identifiers = ["*"]
      }]
      resources = ["arn:aws:es:${var.aws_region}:${var.aws_account_id}:domain/${var.elasticsearch_domain_name}/*"]
    }],)
}

