terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "bucket" {
  bucket_prefix = "my-bucket-"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Subnets
resource "aws_subnet" "first" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[0]
}

resource "aws_subnet" "second" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"

  map_public_ip_on_launch = true
  availability_zone       = data.aws_availability_zones.available.names[1]
}

resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

resource "aws_route_table" "main" {
  vpc_id = aws_vpc.main.id

  route {
    cidr_block = "0.0.0.0/0"
    gateway_id = aws_internet_gateway.main.id
  }
}

resource "aws_route_table_association" "first" {
  subnet_id      = aws_subnet.first.id
  route_table_id = aws_route_table.main.id
}

resource "aws_route_table_association" "second" {
  subnet_id      = aws_subnet.second.id
  route_table_id = aws_route_table.main.id
}

resource "aws_security_group" "first" {
  name        = "test-security-group"
  description = "Allow traffic for Elasticsearch"
  vpc_id      = aws_vpc.main.id
}

resource "aws_vpc_security_group_ingress_rule" "ingress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 80
  ip_protocol = "tcp"
  to_port = 80
}

resource "aws_vpc_security_group_ingress_rule" "ingress2" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 443
  ip_protocol = "tcp"
  to_port = 443
}

resource "aws_vpc_security_group_ingress_rule" "ingress3" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4 = "0.0.0.0/0"
  from_port = 9200
  ip_protocol = "tcp"
  to_port = 9200
}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.first.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_elasticsearch_domain" "test_cluster" {
  domain_name = "es-test"

  cluster_config {
    instance_count         = 2
    zone_awareness_enabled = true
    instance_type          = "t2.small.elasticsearch"
  }

  ebs_options {
    ebs_enabled = true
    volume_size = 10
  }

  vpc_options {
    security_group_ids = [aws_security_group.first.id]
    subnet_ids         = [aws_subnet.first.id, aws_subnet.second.id]
  }
}

data "aws_iam_policy_document" "firehose_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["firehose.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "firehose_role" {
  name               = "firehose_test_role"
  assume_role_policy = data.aws_iam_policy_document.firehose_assume_role.json
}

data "aws_iam_policy_document" "firehose-elasticsearch" {
  statement {
    effect  = "Allow"
    actions = ["es:*"]

    resources = [
      aws_elasticsearch_domain.test_cluster.arn,
      "${aws_elasticsearch_domain.test_cluster.arn}/*",
    ]
  }

  statement {
    effect = "Allow"

    actions = [
      "ec2:DescribeVpcs",
      "ec2:DescribeVpcAttribute",
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeNetworkInterfaces",
      "ec2:CreateNetworkInterface",
      "ec2:CreateNetworkInterfacePermission",
      "ec2:DeleteNetworkInterface",
    ]

    resources = ["*"]
  }
}

resource "aws_iam_role_policy" "firehose-elasticsearch" {
  name   = "elasticsearch"
  role   = aws_iam_role.firehose_role.id
  policy = data.aws_iam_policy_document.firehose-elasticsearch.json
}

resource "aws_kinesis_firehose_delivery_stream" "test" {
  depends_on = [aws_iam_role_policy.firehose-elasticsearch]

  name        = "terraform-kinesis-firehose-es"
  destination = "elasticsearch"

  elasticsearch_configuration {
    domain_arn = aws_elasticsearch_domain.test_cluster.arn
    role_arn   = aws_iam_role.firehose_role.arn
    index_name = "test"
    type_name  = "test"

    s3_configuration {
      role_arn   = aws_iam_role.firehose_role.arn
      bucket_arn = aws_s3_bucket.bucket.arn
    }

    vpc_config {
      subnet_ids         = [aws_subnet.first.id, aws_subnet.second.id]
      security_group_ids = [aws_security_group.first.id]
      role_arn           = aws_iam_role.firehose_role.arn
    }
  }
}

response:
Certainly! Let's outline the steps and requirements for setting up an Amazon Kinesis Data Firehose delivery stream with an Elasticsearch destination within a VPC using Terraform. The steps include:

1. **Define AWS provider**: Specify your AWS provider and appropriate regions.
2. **Create an AWS Elasticsearch domain**: Configure an Elasticsearch domain inside the VPC, specifying readonly policies, access policies, and whether the domain is setup as an outpost.
3. **Configure a VPC and Subnets**: Ensure that the Elasticsearch domain and the Firehose are within the VPC to satisfy the requirement.
4. **Create IAM roles and policies**: IAM roles will be needed for permissions between AWS services and for accessing the Elasticsearch domain.
5. **Configure Kinesis Data Firehose delivery stream**: Set up the Firehose delivery stream to send data to the Elasticsearch domain.

Now, let's translate these step-by-step requirements into Terraform configuration using HCL:

```hcl
provider "aws" {
  region = "us-west-2" # Example region, adjust as necessary
}

resource "aws_iam_role" "firehose_service_role" {
  name = "firehose_service_role"

  assume_role_policy {
    json = jsonencode({
      Version = "2012-10-17"
      Statement = [
        {
          Action = "sts:AssumeRole"
          Effect = "Allow"
          Principal = {
            Service = "firehose.amazonaws.com"
          }
      }
    })
  }
}

resource "aws_iam_role_policy" "firehose_policy" {
  role   = aws_iam_role.firehose_service_role.arn
  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "es:ESHttpGet",
          "es:ESHttpPut",
          "es:ESHttpPost",
          "es:ESHttpPut",
          "kinesis:DescribeStream",
          "kinesis:GetShardIterator",
          "kinesis:ListStreams",
          "kinesis:GetRecords",
          "kinesis:PutRecord",
          "es:ESHttpPost",
          "es:Describe",
          "es:ESSearch",
        ]
        Effect = "Allow"
        Resource = "arn:aws:es:${var.aws_region}:${var.aws_account_id}:domain/${var.elasticsearch_domain_name}/*"
      }
    ]
  })
}

resource "aws_kinesis_firehose_delivery_stream" "firehose_stream" {
  name          = "my-firehose-stream"
  destination_arn = "arn:aws:es:${var.aws_region}:${var.aws_account_id}:domain/${var.elasticsearch_domain_name}/vpc/${var.elasticsearch_domain_endpoint}"

  role_arn = aws_iam_role.firehose_service_role.  arn
  projection {
    type        = "Entity"
    version    = "1.0"

    inline    = {
      "compressionConfiguration": {
        "type": "UNCOMPRESSED"
        "roleARN": aws_iam_role.firehose_service_role.arn
      }
    }
  }
}

resource "aws_vpc" "my_vpc" {
  cidr_block = var.vpc_cidr_block
  enable_dns_support = true
  enable_dns_hostnames = true
}

resource "aws_subnet" "elastic_search_subnet" {
  vpc_id                  = aws_vpc.my_vpc.id
  cidr_block              = "10.0.10.0/24"   # Example CIDR, adjust as necessary
  map_public_ip_on_launch   = false
}

resource "aws_elasticsearch_domain" "my_es_domain" {
  domain_name            = var.elasticsearch_domain_name
  elasticsearch_version = "7.9.3"
  cluster_config {
    instance_type        = "m5.large"
  }
  ebs_options {
    ebs_enabled         = true
    volume_type         = "gp2"
    volume_size         = var.elasticsearch_volume_size
    iops               = var.elasticsearch_volume_iops
  }
  vpc_options {
    domain_subnet_id   = aws_subnet.elastic_search_subnet.id
    security_group_ids = [aws_default_elasticsearch_sg.id] # adjust security group as necessary
    vpc_id            = var.vpc_id
  }
  access_policies = jsonencode([{
    version = "2012-10-17"
    statement = [{
      effect = "Allow"
      actions = ["es:ESHttpPost", "es:ESHttpPut", "es:ESHttpGet"]
      principals = [{
        type = "AWS"
        identifiers = ["*"]
      }]
      resources = ["arn:aws:es:${var.aws_region}:${var.aws_account_id}:domain/${var.elasticsearch_domain_name}/*"]
    }],)
}
```

This HCL code block sets up an Amazon Kinesis Data Firehose delivery stream configured to send data directly into an Elasticsearch domain that is specifically set up within a VPC. Adjust specific variables and resources according to your environment and requirements.

