  role       = aws_iam_role.kda_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AmazonKinesisAnalyticsV2FullAccess"
}

resource "aws_kinesis_analytics_v2_application" "sql_app" {
  name = "kda_sql_app"

  service_execution_role_arn = aws_iam_role.kda_role.arn

  source_configuration {
    application_code_content {
      code = <<-SQL
        CREATE OR REPLACE STREAM "DESTINATION_SQL_STREAM" (
          "device_id" VARCHAR(128),
          "event_time" TIMESTAMP,
          "data" VARCHAR(256)
        );
        CREATE OR REPLACE PUMP "STREAM_PUMP" AS INSERT INTO "DESTINATION_SQL_STREAM"

        SELECT STREAM "device_id", "event_time", "data"
        FROM "SOURCE_SQL_STREAM_001"
        WHERE "event_time" >= CURRENT_TIMESTAMP - INTERVAL '5' MINUTE;
      SQL
    }

    cloud_watch_logging_options {
      log_stream_name = "kda-sql-application-log-stream"
      cloud_watch_log_group_arn = "arn:aws:logs:us-east-1:123456789012:log-group:/aws/kinesis/your-log-group"
      enabled = true
    }

    inputs {
      namePrefix = "SOURCE_SQL_STREAM"

      kinesis_streams_source_configuration {
        kinesis_stream_arn = "arn:aws:kinesis:us-east-1:123456789012:stream/your-kinesis-stream"
        role_arn = aws_iam_role.kda_role.arn
