  type        = string
}

resource "aws_route53_zone" "main_zone" {
  name         = "example.com"
  vpc {
    vpc_id = "vpc-123456"
  }
  zone_id = var.zone_id  // Assume 'main' zone_id will be provided through var file. Ideally, you will use data from Terraform AWS Route 53 by zone module
}

resource "aws_route53_record" "primary_health_check" {
  zone_id         = aws_route53_zone.main_zone.zone_id
  name           = var.hostname
  type           = "A"  // Assuming A record
  ttl            = 60

  records = [
    aws_route53_health_check.primary_health_check.fqdn,
  ]

  failover = "SECONDARY"
  set_identifier = "primary"
}

resource "aws_route53_record" "secondary_health_check" {
  zone_id         = aws_route53_zone.main_zone.zone_id
  name           = var.hostname
  type           = "A"
  ttl            = 60

  records = [
    aws_route53_health_check.secondary_health_check.fqdn,
  ]

  failover = "PRIMARY"
  set_identifier = "secondary"
}

resource "aws_route53_health_check" "primary_health_check" {
  fqdn                = "${aws_route53_record.primary_health_check.name}"
  port                = 80
