To fulfill your request, we will break down the Terraform configuration into several steps:

1. **Create an IAM role** for EKS Fargate profiles that will grant the necessary permissions for pod execution.
2. **Attach the AmazonEKSFargatePodExecutionRolePolicy** to the role.
3. **Create an AWS EKS Fargate profile**, targeting the `kube-system` namespace, and link it to the EKS cluster with the appropriate role and subnets.
4. **Add a `null_resource`** to patch the `coredns` deployment in the `kube-system` namespace. We will use a `local-exec` provisioner to execute the required `kubectl` commands to patch the deployment.

Below is the complete Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_iam_role" "fargate_execution_role" {
  name = "eks-fargate-execution-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "eks-fargate-pods.amazonaws.com"
        }
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "fargate_policy_attachment" {
  role       = aws_iam_role.fargate_execution_role.name
  policy_arn = "arn:aws:iam::aws:policy/AmazonEKSFargatePodExecutionRolePolicy"
}

resource "aws_eks_fargate_profile" "fargate_profile" {
  cluster_name           = "your-eks-cluster-name"
  fargate_profile_name   = "kube-system-fargate-profile"
  pod_execution_role_arn = aws_iam_role.fargate_execution_role.arn
  subnet_ids             = [
    "subnet-0bb1c79de3EXAMPLE", 
    "subnet-0bb1c79de3EXAMPLE2"
  ]

  selector {
    namespace = "kube-system"
  }
}

resource "null_resource" "patch_coredns" {
  triggers = {
    kubeconfig = base64encode(data.aws_eks_cluster_auth.cluster.token)
  }

  provisioner "local-exec" {
    command = <<EOT
      kubectl patch deployment coredns \n        --namespace kube-system \n        --type json \n        -p '[{"op": "add", "path": "/spec/template/metadata/annotations", "value": {"eks.amazonaws.com/compute-type": "FARGATE"}}]' \n        --kubeconfig <(echo $KUBECONFIG) \n        --insecure-skip-tls-verify
EOT

    environment = {
      KUBECONFIG           = data.template_file.kubeconfig.rendered
      EKS_CLUSTER_ENDPOINT = data.aws_eks_cluster.cluster.endpoint
      EKS_CLUSTER_CA       = base64decode(data.aws_eks_cluster.cluster.certificate_authority[0].data)
    }
  }
}

data "aws_eks_cluster" "cluster" {
  name = "your-eks-cluster-name"
}

data "aws_eks_cluster_auth" "cluster" {
  name = "your-eks-cluster-name"
}

data "template_file" "kubeconfig" {
  template = <<EOF
  apiVersion: v1
  clusters:
  - cluster:
      server: ${data.aws_eks_cluster.cluster.endpoint}
      certificate-authority-data: ${data.aws_eks_cluster.cluster.certificate_authority[0].data}
    name: eks-cluster
  contexts:
  - context:
      cluster: eks-cluster
      user: eks-user
    name: eks-context
  current-context: eks-context
  kind: Config
  preferences: {}
  users:
  - name: eks-user
    user:
      exec:
        apiVersion: client.authentication.k8s.io/v1alpha1
        command: aws
        args:
        - eks
        - get-token
        - --cluster-name
        - ${data.aws_eks_cluster.cluster.name}
EOF
}
```

### Key Considerations

- Replace `"your-eks-cluster-name"` with the actual name of your EKS cluster.
- Update `"subnet-0bb1c79de3EXAMPLE"` and `"subnet-0bb1c79de3EXAMPLE2"` with the IDs of the subnets that include the necessary cluster-association resource tag.
- Ensure that Terraform is configured with appropriate permissions and your environment is set up to authenticate with AWS. Adjust the AWS region (`provider "aws" { region = "us-west-2" }`) as necessary.
- Verify that your system's AWS CLI is configured to communicate with your EKS cluster.

