  source  = "git::https://github.com/terraform-aws-modules/terraform-aws-vpc?ref=v2.77.0"
  version = "v2.77.0"

  name = "example"
  cidr_block = "<your-vpc-cidr-block>"
  azs = ["<your-az1>", "<your-az2>"]
  private_subnets = ["<subnet-id-1>", "<subnet-id-2>"]
  public_subnets  = ["<public-subnet-id-1>", "<public-subnet-id-2>"]
  enable_dns_hostnames = true
  enable_dns_support    = true

  tags = {
    Owner = "example"
  }
}

resource "aws_eks_cluster" "example" {
  name     = "example"
  role_arn = data.aws_iam_role.example_eks_role.arn

  vpc_config {
    cluster_name   = "example"
    vpc_id         = aws_vpc.example.id
    security_group_ids = ["<your-security-group-id>"]
    endpoint_private_access CIDRs = ["<your-private-cidr-access>"]
    endpoint_public_access CIDRs  = ["0.0.0.0/0"]
  }

  depends_on = [
    aws_iam_role_policy_attachment.example_policy_eks,
