To create Terraform configurations for AWS that set up a VPC with three subnets (one public and two private) and deploy EC2 instances and an RDS database instance as required, we will follow these steps:

1. **Define the AWS Provider**: Specify the provider for AWS along with your access keys or other preferred authentication method.
2. **Create a VPC**: Set up the VPC with an internet gateway to allow internet access for the public subnet.
3. **Create Subnets**: Designate one public subnet and two private subnets within the VPC.
4. **Create EC2 Instances**: Deploy EC2 instances for hosting web servers and application servers in the respective subnets.
5. **Create an RDS Instance**: Deploy the RDS database in one of the private subnets.

### Terraform Configuration in HCL:

```hcl
provider "aws" {
  region = "us-west-2"  # Replace with your preferred region
  # Specify access configurations here or config them via environment variables or credentials file
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_internet_gateway" "gw" {
  vpc_id = aws_vpc.main.id
}

resource "aws_subnet" "public" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.1.0/24"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private1" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.2.0/24"
  availability_zone = "us-west-2a"  # Ensure this matches the region
}

resource "aws_subnet" "private2" {
  vpc_id            = aws_vpc.main.id
  cidr_block         = "10.0.3.0/24"
  availability_zone = "us-west-2b"  # Ensure this matches the region
}

resource "aws_instance" "web_server" {
  ami           = "ami-0c55b159cbfafe1fe"  # Replace with an appropriate AMI
  instance_type = "t2.micro"  # Adjust as per your requirement
  subnet_id     = aws_subnet.public.id
  key_name      = "your-key-pair-name"  # Replace with your SSH key pair name

  tags = {
    Name = "WebServer"
  }
}

resource "aws_instance" "app_server" {
  ami           = "ami-01b6c6be5f07ae6b0"  # Replace with an appropriate AMI
  instance_type = "t2.micro"  # Adjust as per your requirement
  subnet_id     = aws_subnet.private1.id
  key_name      = "your-key-pair-name"  # Replace with your SSH key pair name

  tags = {
    Name = "AppServer"
  }
}

resource "aws_db_instance" "default_db_instance" {
  instance_class            = "db.t2.micro"
  allocated_storage        = 20
  db_name                 = "mydatabase"
  engine                  = "mysql"
  engine_version          = "5.7.22"
  username                = "dbadmin"
  password                = "securepassword"
  parameter_group_name    = "default.mysql5.7"
  db_subnet_group_name    = aws_db_subnet_group.default.name
  skip_final_snapshot    = true

  tags = {
    Name = "MyDBInstance"
  }
}

resource "aws_db_subnet_group" "default" {
  name        = "default"
  subnet_ids   = [aws_subnet.private2.id]
  db_subnet_filter {
    type = "isolated"
  }
}

resource "aws_instance" "web_server" {
  ami           = "ami-0c55b159cbfafe1fe"  # Use the AMI of your choice
  instance_type = "t2.micro"              # Choose the instance size according to your need
  subnet_id     = aws_subnet.private1.id
  key_name      = "your-key-pair-name"

  tags = {
    Name = "WebServer1"
  }
}
```

