    version = "2012-10-17"
    statement = "{
      'Effect': 'Allow',
      'Principal': {
        'Service': 'redshift.amazonaws.com'
      },
      'Action': 'sts:AssumeRole'
    }"
  }
}

resource "aws_redshift_cluster_identifier" "cluster_id" {
