response:
To create an AWS Lambda function using Terraform, we need to follow these steps:

1. Define an IAM role that the Lambda function will assume.
2. Create an IAM policy with a trust relationship that allows the Lambda service to assume the role.
3. Attach a managed policy that grants the necessary permissions for the Lambda function.
4. Define the Lambda function, specifying its runtime, handler, and source code location.

Here's the complete Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"  # Specify the desired region
}

resource "aws_iam_role" "lambda_role" {
  name = "lambda_execution_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Principal = {
          Service = "lambda.amazonaws.com"
        }
        Effect = "Allow"
        Sid    = ""
      },
    ]
  })
}

resource "aws_iam_policy_attachment" "lambda_basic_execution" {
  name       = "lambda_basic_execution"
  roles      = [aws_iam_role.lambda_role.name]
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSLambdaBasicExecutionRole"
}

resource "aws_lambda_function" "example_lambda" {
  filename         = data.archive_file.lambda_zip.output_path
  function_name    = "example_lambda_function"
  role             = aws_iam_role.lambda_role.arn
  handler          = "lambda.handler"
  runtime          = "nodejs18.x"
  source_code_hash = data.archive_file.lambda_zip.output_base64sha256

  depends_on = [
    aws_iam_policy_attachment.lambda_basic_execution,
  ]
}

data "archive_file" "lambda_zip" {
  type        = "zip"
  source_file = "lambda.js"
  output_path = "lambda_package.zip"
}
```

This configuration defines:
- The IAM role with a trust policy for the Lambda service.
- The attachment of the AWS managed policy required for basic Lambda execution.
- The Lambda function itself, which uses Node.js 18.x and the specified handler (`lambda.handler`), with the code sourced from `lambda.js` and zipped.
- Ensure that the `lambda.js` file exists in the same directory as the Terraform configuration when you apply it.

