extracted_code:
provider "aws" {
  region = "us-east-1"
}

data "aws_ami" "latest_amazon_linux" {
  filters = {
    name = "amzn2-ami-hvm*"
    root-device-type = "ebs"
  }
  most_recent = true
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_hostnames = true
  enable_dns_support   = true
}

resource "aws_subnet" "public" {
  vpc_id = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  map_public_ip_on_launch = true
}

resource "aws_subnet" "private" {
  vpc_id = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  map_public_ip_on_launch = false
}

resource "aws_launch_template" "instance_template" {
  name          = "instance-template"
  image_id      = data.aws_ami.latest_amazon_linux.id
  instance_type = "t3.medium"
  key_name      = "your-key-name"
  user_data     = file("init_script.sh")

  network_interfaces {
    associate_public_ip_address = true
    security_groups = ["your-security-group"]
  }
}

resource "aws_autoscaling_group" "ec2_fleet" {
  name                   = "EC2Fleet"
  max_size               = 9
  min_size               = 1
  desired_capacity       = 9
  launch_template        = aws_launch_template.instance_template.id

  tag {
    key                 = "Name"
    value               = "EC2Instance"
    propagate_at_launch = true
  }

  vpc_zone_identifier = [aws_subnet.public.id]
}

resource "aws_spot_instance_request" "spot_instances" {
  spot_price       = "0.03"
  instance_interrruptions_action = "stop"
  instance_type = "t3.medium"
}

resource "aws_autoscaling_attachment" "spot_attachment" {
  group = aws_autoscaling_group.ec2_fleet.id
  instance_id = aws_spot_instance_request.spot_instances.id
  weight = 0
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

# Create a Virtual Private Cloud (VPC)
resource "aws_vpc" "my_vpc" {
  cidr_block = "10.0.0.0/16"
}

data "aws_availability_zones" "available" {
  state = "available"
}

# Create Public Subnet
resource "aws_subnet" "public_subnet" {
  vpc_id                  = aws_vpc.my_vpc.id
  cidr_block              = "10.0.1.0/24"
  availability_zone       = data.aws_availability_zones.available.names[0]
  map_public_ip_on_launch = true
}

# Create Private Subnet
resource "aws_subnet" "private_subnet" {
  vpc_id            = aws_vpc.my_vpc.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = data.aws_availability_zones.available.names[1]
}


data "aws_ami" "latest_amazon_linux_2" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

# Create Launch Template for EC2 instances
resource "aws_launch_template" "ec2_launch_template" {
  name = "my-launch-template"

  instance_type = "t2.micro"
  image_id = data.aws_ami.latest_amazon_linux_2.id
}

# Create EC2 Fleet
resource "aws_ec2_fleet" "ec2_fleet" {
  launch_template_config {
    launch_template_specification {
      launch_template_id = aws_launch_template.ec2_launch_template.id
      version            = aws_launch_template.ec2_launch_template.latest_version
    }
  }

  target_capacity_specification {
    default_target_capacity_type = "on-demand"
    total_target_capacity        = 9
    on_demand_target_capacity    = 5
    spot_target_capacity         = 4
  }

  excess_capacity_termination_policy = "termination"
  replace_unhealthy_instances = true
  terminate_instances = true

  # Additional configurations can be added as needed
}

