  }
}

resource "aws_security_group" "msk_cluster_security_group" {
  name   = "msk_cluster_security_group"
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port   = 9092
    to_port     = 9092
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust as needed for your use case
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk_cluster_security_group"
  }
}

resource "aws_security_group" "msk_worker_security_group" {
