    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "msk_worker_security_group"
  }
}

resource "aws_msk_cluster" "msk_example" {
  cluster_name            = "msk-cluster"
  kafka_version           = "2.8.1"
  number_of_broker_nodes  = 3
  enhanced_monitoring     = "PER_BROKER"
  kafka_broker_instance_type = "kafka.m5.large"
  kafka_broker_storage_info {
    ebs_volume_size = 100
  }

  broker_node_group_info {
    zk_connect_string = aws_msk_cluster.msk_example.zookeeper_connect_string
    client_subnets = [aws_subnet.msk_subnet.id]
    security_groups = [aws_security_group.msk_cluster_security_group.id]
    instance_type = "kafka.m5.large"
    ebs_volume_type = "gp2"
    storage_encrypted = false
  }

