  cidr_block = count.index == 0 ? "10.0.1.0/24" : "10.0.2.0/24"
  availability_zone = count.index == 0 ? "us-east-1a" : "us-east-1b"
  map_public_ip_on_launch = true

  tags = {
    Name = "msk_subnet-${count.index}"
  }
}

resource "aws_security_group" "msk_sg" {
  vpc_id = aws_vpc.msk_vpc.id

  ingress {
    from_port = 0
    to_port = 0
    protocol = "-1"
    cidr_blocks = ["10.0.0.0/16"]
  }

  tags = {
    Name = "msk_security_group"
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "firehose_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Principal = {
          Service = "firehose.amazonaws.com"
        },
        Action = "sts:AssumeRole"
      }
    ]
  })
}

resource "aws_iam_policy" "firehose_policy" {
  name = "firehose_policy"
  policy = jsonencode({
    Version = "2012-10-17",
    Statement = [
      {
        Effect = "Allow",
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ],
        Resource = [
          "arn:aws:s3:::msk-logs-bucket/*",
          "arn:aws:s3:::msk-logs-bucket"
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "firehose_policy_attachment" {
  role       = aws_iam_role.firehose_role.name
  policy_arn = aws_iam_policy.firehose_policy.arn
}

resource "aws_s3_bucket" "msk_logs_bucket" {
  bucket = "msk-logs-bucket"
  acl    = "private"
  force_destroy = true
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-firehose"
  destination = "extended_s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs_bucket.arn

    buffering {
      interval_in_seconds = 300
      size_in_m_bs        = 128
    }

    compression_format = "UNCOMPRESSED"

    cloudwatch_logging_options {
      enabled = true
      log_group_name = "firehose-msk-logs"
      log_stream_name = "firehose-msk"
    }
  }
}

resource "aws_msk_cluster" "msk_cluster" {
  cluster_name = "msk-cluster"
  kafka_version = "2.6.1"
  number_of_broker_nodes = 3

  broker_node_group_info {
    instance_type = "kafka.t3.small"
    ebs_volumes {
      volume_size = 25
    }
    client_subnets = [for subnet in aws_subnet.msk_subnet : subnet.id]
    security_groups = [aws_security_group.msk_sg.id]
