}

resource "aws_vpc_security_group_egress_rule" "egress1" {
  security_group_id = aws_security_group.sg.id
  cidr_ipv4         = "0.0.0.0/0"
  ip_protocol       = "-1"
}

resource "aws_kms_key" "kms" {
    description = "example"
}

resource "aws_cloudwatch_log_group" "test" {
    name = "msk_broker_logs"
}

resource "aws_s3_bucket" "bucket" {
    bucket_prefix = "msk-broker-logs-"
}

resource "aws_s3_bucket_ownership_controls" "example" {
    bucket = aws_s3_bucket.bucket.id
    rule {
        object_ownership = "BucketOwnerPreferred"
    }
}

resource "aws_s3_bucket_acl" "example" {
    depends_on = [aws_s3_bucket_ownership_controls.example]

    bucket = aws_s3_bucket.bucket.id
    acl = "private"
}

data "aws_iam_policy_document" "assume_role" {
    statement {
        effect = "Allow"
        principals {
            type = "Service"
            identifiers = ["firehose.amazonaws.com"]
        }
        actions = ["sts:AssumeRole"]
    }
}

resource "aws_iam_role" "firehose_role" {
    name = "firehose_test_role"
    assume_role_policy = data.aws_iam_policy_document.assume_role.json
}

resource "aws_kinesis_firehose_delivery_stream" "test_stream" {
    name = "terraform-kinesis-firehose-msk-broker-logs-stream"
    destination = "extended_s3"

    extended_s3_configuration {
        role_arn = aws_iam_role.firehose_role.arn
        bucket_arn = aws_s3_bucket.bucket.arn
    }

    tags = {
        LogDeliveryEnabled = "placeholder"
    }

    lifecycle {
        ignore_changes = [
            tags["LogDeliveryEnabled"],
        ]
    }
}

resource "aws_msk_cluster" "example" {
    cluster_name = "example"
    kafka_version = "3.2.0"
    number_of_broker_nodes = 3

    broker_node_group_info {
        instance_type = "kafka.t3.small"
        client_subnets = [
            aws_subnet.subnet_az1.id,
            aws_subnet.subnet_az2.id,
            aws_subnet.subnet_az3.id,
        ]
        storage_info {
            ebs_storage_info {
                volume_size = 1000
            }
        }
        security_groups = [aws_security_group.sg.id]
    }

    encryption_info {
        encryption_at_rest_kms_key_arn = aws_kms_key.kms.arn
    }

    open_monitoring {
        prometheus {
            jmx_exporter {
                enabled_in_broker = true
            }
            node_exporter {
                enabled_in_broker = true
            }
        }
    }

    logging_info {
        broker_logs {
            cloudwatch_logs {
                enabled = true
                log_group = aws_cloudwatch_log_group.test.name
            }
            firehose {
                enabled = true
                delivery_stream = aws_kinesis_firehose_delivery_stream.test_stream.name
            }
            s3 {
                enabled = true
                bucket = aws_s3_bucket.bucket.id
                prefix = "logs/msk-"
            }
        }
    }
}

output "zookeeper_connect_string" {
    value = aws_msk_cluster.example.zookeeper_connect_string
}

output "bootstrap_brokers_tls" {
    description = "TLS connection host:port pairs"
    value = aws_msk_cluster.example.bootstrap_brokers_tls
}

response:
To set up an Amazon MSK cluster with the specified features, we'll break down the requirements into steps and define the Terraform configuration accordingly:

1. **Create an MSK Cluster**: We'll create an MSK cluster with three broker instances.

2. **Enable Encryption at Rest**: We'll configure server-side encryption for the MSK cluster using an AWS KMS key.

3. **Set Up Monitoring**:
   - Open monitoring: This is enabled by default in newer versions of MSK, but we'll ensure it's configured.
   - Integrate with CloudWatch Logs: We'll specify to enable logging of broker logs to a CloudWatch Logs group.

4. **Create a CloudWatch Logs Group**: This will be used by MSK brokers to send their logs.

5. **Set Up S3 Bucket**: This bucket will be used to store a predefined aspect of MSK (e.g., metrics), or logs if configured separately somewhere.

6. **Create a Kinesis Data Firehose Delivery Stream**: This can be used for forwarding logs from CloudWatch to S3 if needed.

Here's the full Terraform configuration in HCL:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_kms_key" "msk_encryption_key" {
  description             = "KMS Key for MSK Encryption"
  deletion_window_in_days = 10
}

resource "aws_cloudwatch_log_group" "msk_broker_logs" {
  name = "/aws/msk/kafka-cluster"
}

resource "aws_s3_bucket" "msk_logs" {
  bucket = "msk-cluster-logs"
  acl    = "private"
}

resource "aws_cloudwatch_log_group" "firehose_destination_logs" {
  name = "/aws/firehose/msk-cluster-firehose-logs"
}

resource "aws_kinesis_firehose_delivery_stream" "msk_firehose" {
  name        = "msk-kafka-firehose"
  destination = "s3"

  s3_configuration {
    role_arn   = aws_iam_role.firehose_role.arn
    bucket_arn = aws_s3_bucket.msk_logs.arn

    cloudwatch_logging_options {
      log_group_name = aws_cloudwatch_log_group.firehose_destination_logs.name
      enabled        = true
    }
  }
}

resource "aws_iam_role" "firehose_role" {
  name = "msk-firehose-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "firehose.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_role_policy" "firehose_policy" {
  name = "firehose-access-policy"
  role = aws_iam_role.firehose_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = [
          "s3:AbortMultipartUpload",
          "s3:GetBucketLocation",
          "s3:GetObject",
          "s3:ListBucket",
          "s3:ListBucketMultipartUploads",
          "s3:PutObject"
        ]
        Effect = "Allow"
        Resource = [
          aws_s3_bucket.msk_logs.arn,
          "${aws_s3_bucket.msk_logs.arn}/*"
        ]
      },
      {
        Action = [
          "logs:CreateLogStream",
          "logs:PutLogEvents"
        ]
        Effect = "Allow"
        Resource = aws_cloudwatch_log_group.firehose_destination_logs.arn
      }
    ]
  })
}

resource "aws_msk_cluster" "kafka_cluster" {
  hostname                   = "kafka-cluster"
  kafka_version              = "2.8.0"
  number_of_broker_nodes     = 3
  broker_node_group_info {
    instance_type       = "kafka.m5.large"
    ebs_volume_size     = 1000
    client_subnets      = ["subnet-0bb1c79de3EXAMPLE", "subnet-0bb1c79de3EXAMPLE", "subnet-0bb1c79de3EXAMPLE"]
    security_group_ids  = ["sg-0bb1c79de3EXAMPLE"]
    storage_info {
      ibmblock_device {
        volume_size = 1000
      }
    }
  }
  encryption_info {
    encryption_at_rest_kms_key_arn = aws_kms_key.msk_encryption_key.arn
  }
  open_monitoring_kafka_endpoint {
    auth {
      type = "PLAINTEXT"
    }
    tls {
      type = "NONE"
    }
  }
  logging_info {
    broker_logs {
      cloudwatch_logs {
        enabled   = true
        log_group = aws_cloudwatch_log_group.msk_broker_logs.name
      }
      firehose {
        enabled   = true
        delivery_stream = aws_kinesis_firehose_delivery_stream.msk_firehose.name
      }
    }
  }
}

output "msk_cluster_arn" {
  value = aws_msk_cluster.kafka_cluster.arn
}

output "msk_cluster_bootstrap_brokers" {
  value = aws_msk_cluster.kafka_cluster.bootstrap_brokers
}
```

### Explanation:

- **AWS Provider**: Specify the region for the AWS resources.

- **Infrastructure**:
  - **KMS Key**: Used for encryption at rest.
  - **CloudWatch Log Groups**: Both for the brokers and the Firehose destination.
  - **S3 Bucket**: Holds logs delivered by Firehose.
  - **Kinesis Firehose**: Configured to forward logs from CloudWatch to S3.
  - **IAM Role and Policy**: Grant permissions for the Firehose to access S3 and CloudWatch Logs.

- **MSK Cluster**: Configure with broker nodes, enable encryption, and specify logging to CloudWatch and Firehose. Adjust the subnets and security groups according to your VPC setup.

