response:
To set up a MySQL cluster with 100 GB of storage distributed across the availability zones `us-east-1a`, `us-east-1b`, and `us-east-1c`, we need to configure an RDS instance with Multi-AZ deployments for high availability. We'll also configure the instance to have provisioned storage and place replicas in specified availability zones using AWS's Aurora Database with MySQL Compatibility.

Let's break down the task step-by-step:

1. **Provider Configuration**: Define the AWS provider and specify the region `us-east-1`.

2. **VPC and Subnets**: Create a VPC and subnets for each of the availability zones (`us-east-1a`, `us-east-1b`, and `us-east-1c`). The RDS instance will be deployed in these subnets.

3. **RDS Cluster Creation**: We'll create an Aurora Cluster using the MySQL engine. This involves setting database parameters, capacity configurations and storage settings.

Here is the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "subnet_a" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a"
  tags = {
    Name = "subnet-us-east-1a"
  }
}

resource "aws_subnet" "subnet_b" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.2.0/24"
  availability_zone = "us-east-1b"
  tags = {
    Name = "subnet-us-east-1b"
  }
}

resource "aws_subnet" "subnet_c" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.3.0/24"
  availability_zone = "us-east-1c"
  tags = {
    Name = "subnet-us-east-1c"
  }
}

resource "aws_db_subnet_group" "main" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.subnet_a.id, aws_subnet.subnet_b.id, aws_subnet.subnet_c.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_rds_cluster" "cluster" {
  cluster_identifier      = "my-mysql-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "5.7.mysql_aurora.2.07.2" # Ensure compatibility version
  db_subnet_group_name    = aws_db_subnet_group.main.name
  availability_zones      = ["us-east-1a", "us-east-1b", "us-east-1c"]
  master_username         = "root"
  master_password         = var.db_master_password
  skip_final_snapshot     = true
  db_cluster_parameter_group_name = aws_rds_cluster_parameter_group.default.name
}

resource "aws_rds_cluster_instance" "instance" {
  count               = 2 # Cluster instance count 
  identifier          = "my-mysql-cluster-instance-${count.index}"
  cluster_identifier  = aws_rds_cluster.cluster.id
  engine              = "aurora-mysql"
  engine_version      = "5.7.mysql_aurora.2.07.2"
  instance_class      = "db.r5.large"
  db_subnet_group_name = aws_db_subnet_group.main.name
  availability_zone   = ["us-east-1a", "us-east-1b", "us-east-1c"][count.index % 3]
}

resource "aws_rds_cluster_parameter_group" "default" {
  name   = "default-cluster-param-group"
  family = "aurora-mysql5.7"

  parameter {
    name  = "character_set_server"
    value = "utf8mb4"
  }

  parameter {
    name  = "collation_server"
    value = "utf8mb4_unicode_ci"
  }
}

variable "db_master_password" {
  description = "The master password for the RDS instance"
}

output "cluster_endpoint" {
  value = aws_rds_cluster.cluster.endpoint
}

output "reader_endpoint" {
  value = aws_rds_cluster.cluster.reader_endpoint
}
```

**Note**: Replace the `var.db_master_password` with the actual master password using a secure method, such as fetching from a secrets management system or using environment variables setting. Also, ensure to adjust `db_cluster_parameter_group_name`, `engine_version`, and `instance_class` according to specific needs and AWS capability.

