  tags = {
    Name = "my_subnet"
  }
}

resource "aws_network_acl" "my_network_acl" {
  vpc_id = aws_vpc.my_vpc.id

  tags = {
    Name = "my_network_acl"
  }
}

resource "aws_network_acl_rule" "ingress_rule" {
  network_acl_id = aws_network_acl.my_network_acl.id
  rule_number    = 100
  egress         = false
  protocol       = "tcp"
  rule_action    = "allow"
  cidr_block     = "0.0.0.0/0"
