Certainly! To create an AWS Neptune cluster with a custom cluster parameter group, and a Neptune instance with a separate custom instance parameter group, we'll need to follow these steps:

1. Define a custom cluster parameter group.
2. Define a custom instance parameter group.
3. Create the Neptune cluster using the custom cluster parameter group.
4. Add an instance to the Neptune cluster using the custom instance parameter group.

Here is the Terraform configuration in HCL to achieve this:

```hcl
provider "aws" {
  region = "us-west-2" # You can choose your preferred region
}

resource "aws_db_parameter_group" "neptune_cluster_param_group" {
  name   = "neptune-custom-cluster-param-group"
  family = "neptune3.0"

  parameter {
    name  = "log_statement"
    value = "all"
  }
}

resource "aws_db_instance" "neptune_param_group" {
  name               = "neptune-custom-instance-param-group"
  family             = "neptune3.0"
  engine             = "neptune"
  apply_immediately  = true

  parameter {
    name  = "log_javascript_parser_errors"
    value = "1"
  }
}

resource "aws_neptune_cluster" "example" {
  cluster_identifier      = "neptune-example-cluster"
  engine                  = "neptune"
  engine_version          = "3.0.3"
  db_cluster_parameter_group_name = aws_db_parameter_group.neptune_cluster_param_group.id
}

resource "aws_neptune_cluster_instance" "example_instance" {
  cluster_identifier = aws_neptune_cluster.example.id
  instance_class     = "db.r5.large"
  identifier         = "neptune-example-instance"
  publicly_accessible = true

  db_parameter_group_name = aws_db_instance.neptune_param_group.name
}
```

Make sure to replace the region with your desired AWS region and adjust any other parameters as needed. This configuration sets up a Neptune cluster and adds an instance using custom parameter groups.

