response:
To fulfill this request, we need to break down the requirements into detailed steps and generate the corresponding Terraform configuration in HCL format. Here's the plan:

1. **Create a VPC** with a subnet where the Neptune cluster will reside.
2. **Create a custom DB cluster parameter group** to adjust cluster-wide settings.
3. **Create a Neptune cluster** using the custom parameter group.
4. **Create a custom DB instance parameter group** to adjust instance-specific settings.
5. **Launch a Neptune instance** in the cluster using the custom instance parameter group.
6. **Restrict access** so only the subnet can connect to the Neptune instance.

Here is the complete Terraform configuration for the described setup:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "example" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example" {
  vpc_id     = aws_vpc.example.id
  cidr_block = "10.0.1.0/24"
}

resource "aws_db_subnet_group" "example" {
  name       = "example"
  subnet_ids = [aws_subnet.example.id]

  tags = {
    Name = "NeptuneSubnetGroup"
  }
}

resource "aws_db_cluster_parameter_group" "example_cluster" {
  name   = "example-cluster-parameter-group"
  family = "neptune1"

  parameter {
    name  = "neptune_enable_cloudwatch_logs_exports"
    value = "true" // Example parameter for enabling CloudWatch logs
  }

  tags = {
    Name = "NeptuneClusterParameterGroup"
  }
}

resource "aws_neptune_cluster" "example_cluster" {
  cluster_identifier      = "example-cluster"
  database_name           = "neptune"
  master_username         = "neptuneadmin"
  master_password         = "SuperSecret" # Make sure to handle this securely
  db_subnet_group_name    = aws_db_subnet_group.example.name
  cluster_parameter_group_name = aws_db_cluster_parameter_group.example_cluster.name
}

resource "aws_db_instance" "example_instance" {
  identifier               = "example-instance"
  instance_class           = "db.r5.large"
  engine                   = "neptune"
  cluster_identifier       = aws_neptune_cluster.example_cluster.id
  db_subnet_group_name     = aws_db_subnet_group.example.name
  instance_parameter_group_name = aws_db_parameter_group.example_instance.name
}

resource "aws_db_parameter_group" "example_instance" {
  name   = "example-instance-parameter-group"
  family = "neptune1"

  parameter {
    name  = "cpu_core_count"
    value = "2" // Example setting for the instance
  }

  tags = {
    Name = "NeptuneInstanceParameterGroup"
  }
}

resource "aws_security_group" "example_sg" {
  name        = "example-neptune-sg"
  description = "Security group for Neptune instance"
  vpc_id      = aws_vpc.example.id

  ingress {
    from_port   = 8182
    to_port     = 8182
    protocol    = "tcp"
    cidr_blocks = [aws_subnet.example.cidr_block]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_neptune_cluster_parameter_group" "example_cluster" {
  name   = "example-cluster-parameter-group"
  family = "neptune1"

  parameter {
    name  = "neptune_enable_cloudwatch_logs_exports"
    value = "true"
  }

  tags = {
    Name = "ClusterParameterGroup"
  }
}

resource "aws_neptune_cluster_instance" "example_instance" {
  count               = 1
  identifier          = "example-instance-${count.index}"
  cluster_identifier  = aws_neptune_cluster.example_cluster.id
  instance_class      = "db.r5.large"
  db_subnet_group_name = aws_db_subnet_group.example.name
  publicly_accessible = false

  security_group_ids = [aws_security_group.example_sg.id]
}

output "cluster_endpoint" {
  value = aws_neptune_cluster.example_cluster.endpoint
}
```

### Explanation:
- **VPC and Subnet**: Created a VPC and subnet for the cluster and instance.
- **DB Subnet Group**: Ensures that DB resources are created within the subnet.
- **Cluster Parameter Group**: Custom parameter group for the Neptune cluster.
- **Neptune Cluster**: Basic setup with a master username and password.
- **Instance Parameter Group**: Custom parameter group for the instance.
- **Neptune Instance**: Launched in the Neptune cluster.
- **Security Group**: Restricts access to port 8182 (default Neptune port) only to the subnet.
- **Output**: Prints the Neptune cluster endpoint.

The username and password are included directly in the example; in production, use AWS Secrets Manager or a similar service for secure handling. Adjust other parameters as necessary for your environment.

