  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "artifact_bucket" {
  bucket_prefix = "artifact-bucket-"
}

resource "aws_codebuild_project" "autograder_build" {
  name         = "autograder_build"
  service_role = aws_iam_role.autograder_build_role.arn

  artifacts {
    type     = "S3"
    location = aws_s3_bucket.artifact_bucket.arn
    name     = "results.zip" # include this
  }

  environment { # arguments required, exact value not specified
    compute_type = "BUILD_GENERAL1_SMALL"
    image        = "aws/codebuild/standard:7.0-24.10.29"
    type         = "LINUX_CONTAINER"
  }

  source {
    type            = "GITHUB"
    git_clone_depth = 1 # good to have, not required
    location        = "github.com/source-location"
  }

  vpc_config {
    vpc_id             = aws_vpc.autograder_vpc.id
    subnets            = [aws_subnet.autograder_vpc_subnet.id]
    security_group_ids = [aws_security_group.autograder_vpc_securitygroup.id]
  }
}

resource "aws_vpc" "autograder_vpc" {
  cidr_block = "10.0.0.0/16" # extra value not specified
}

resource "aws_subnet" "autograder_vpc_subnet" {
  vpc_id     = aws_vpc.autograder_vpc.id
  cidr_block = "10.0.0.0/24" # include this
}

resource "aws_security_group" "autograder_vpc_securitygroup" {
  vpc_id = aws_vpc.autograder_vpc.id
}

resource "aws_iam_role" "autograder_build_role" {
  assume_role_policy = data.aws_iam_policy_document.autograder_build_policy_assume.json
}

data "aws_iam_policy_document" "autograder_build_policy_assume" {
  statement {
    actions = ["sts:AssumeRole"]

    principals {
      type        = "Service"
      identifiers = ["codebuild.amazonaws.com"]
    }
  }
}

data "aws_iam_policy_document" "autograder_build_policy" {
  statement {
    effect = "Allow"
    actions = [
      "ec2:DescribeSubnets",
      "ec2:DescribeSecurityGroups",
      "ec2:DescribeVpcs"
    ]
    resources = [
      "*"
    ]
  }

  statement {
    effect  = "Allow"
    actions = ["s3:*"]
    resources = [
      aws_s3_bucket.artifact_bucket.arn,
      "${aws_s3_bucket.artifact_bucket.arn}/*",
    ]
  }
}

resource "aws_iam_policy" "autograder_build_policy" {
  name        = "lambda_policy"
  description = "Grants permissions to Lambda to describe vpc, subnet, security group"

  policy = data.aws_iam_policy_document.autograder_build_policy.json
}

resource "aws_iam_role_policy_attachment" "lambda_policy_attach" {
  role       = aws_iam_role.autograder_build_role.name
  policy_arn = aws_iam_policy.autograder_build_policy.arn
}

response:
To meet the requirements, we will follow a step-by-step approach to define each resource:

1. **Create an S3 Bucket**: This bucket will be used for storing code build artifacts.  
2. **Create a VPC**: Allocate a `/16` CIDR block for the VPC and a `/24` subnet within that VPC.
3. **Create a Security Group**: This security group is associated with the VPC above and has no ingress or egress rules to fully block internet access.
4. **Create a CodeBuild Project**: The project must be configured to:
   - Use the created S3 bucket for storing artifacts.
   - Operate within the defined VPC and subnet.
   - Use an environment setup as specified.

Here is the Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"  # Specify your preferred region
}

resource "aws_s3_bucket" "build_artifacts" {
  bucket = "student-build-artifacts"
  acl    = "private"
}

resource "aws_vpc" "default_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "default_subnet" {
  vpc_id     = aws_vpc.default_vpc.id
  cidr_block = "10.0.0.0/24"
}

resource "aws_security_group" "no_access_sg" {
  name_prefix = "no-internet-access-"
  vpc_id      = aws_vpc.default_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = []
  }
}

resource "aws_codebuild_project" "github_codebuild" {
  name          = "github-build-project"
  description   = "Build project for student artifacts"
  build_timeout = "5"
  service_role  = aws_iam_role.codebuild_role.arn

  artifacts {
    type = "S3"
    location = aws_s3_bucket.build_artifacts.bucket
  }

  environment {
    compute_type    = "BUILD_GENERAL1_SMALL"
    image           = "aws/codebuild/amazonlinux2-x86_64-standard:3.0"
    type            = "LINUX_CONTAINER"
    environment_variable {
      name  = "SOME_VARIABLE"
      value = "some_value"
    }
  }

  source {
    type            = "GITHUB"
    location        = "https://github.com/source-location"
    git_clone_depth = 1
  }

  vpc_config {
    vpc_id           = aws_vpc.default_vpc.id
    subnets          = [aws_subnet.default_subnet.id]
    security_groups  = [aws_security_group.no_access_sg.id]
  }
}

resource "aws_iam_role" "codebuild_role" {
  name               = "codebuild-demo"
  assume_role_policy = jsonencode({
    Version   = "2012-10-17"
    Statement = [{
      Action    = "sts:AssumeRole"
      Effect    = "Allow"
      Principal = { Service = "codebuild.amazonaws.com" }
    }]
  })
}

resource "aws_iam_role_policy_attachment" "codebuild_policy" {
  role       = aws_iam_role.codebuild_role.name
  policy_arn = "arn:aws:iam::aws:policy/AWSCodeBuildAdminAccess"
}

resource "aws_iam_role_policy" "allow_s3_access" {
  name = "AllowAccessToS3"
  role = aws_iam_role.codebuild_role.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect   = "Allow"
        Action   = [
          "s3:GetObject",
          "s3:PutObject",
          "s3:ListBucket"
        ]
        Resource = [
          aws_s3_bucket.build_artifacts.arn,
          "${aws_s3_bucket.build_artifacts.arn}/*"
        ]
      }
    ]
  })
}
```

### Explanation:

- **S3 Bucket**: A simple configuration for an S3 bucket is set up with private access.
- **VPC**: A VPC is created using a `/16` CIDR block, allowing multiple subnets.
- **Subnet**: A subnet is set up within the VPC with a `/24` CIDR block.
- **Security Group**: Configured to block all ingress and egress traffic.
- **CodeBuild Project**: Configured to use the specified environment and source settings with VPC integration points.
- **IAM Role**: Ensures the CodeBuild project is able to manage S3 and assume the role securely.

