  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  resource_id = aws_api_gateway_resource.photos.id
  http_method = aws_api_gateway_method.random_method.http_method

  integration_http_method = "POST"
  type                    = "AWS_PROXY"
  uri                     = aws_lambda_function.random_image.invoke_arn
}

resource "aws_lambda_permission" "allow_apigateway" {
  statement_id  = "AllowExecutionFromAPIGateway"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.upload.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

resource "aws_lambda_permission" "allow_apigateway_random" {
  statement_id  = "AllowExecutionFromAPIGatewayRandom"
  action        = "lambda:InvokeFunction"
  function_name = aws_lambda_function.random_image.function_name
  principal     = "apigateway.amazonaws.com"

  source_arn = "${aws_api_gateway_rest_api.cat_api.execution_arn}/*/*"
}

resource "aws_api_gateway_deployment" "deploy" {
  depends_on = [
    aws_api_gateway_integration.upload_integration,
    aws_api_gateway_integration.random_integration
  ]

  rest_api_id = aws_api_gateway_rest_api.cat_api.id
  stage_name  = "prod"
}

resource "aws_api_gateway_stage" "prod_stage" {
  deployment_id = aws_api_gateway_deployment.deploy.id
  rest_api_id   = aws_api_gateway_rest_api.cat_api.id
  stage_name    = "prod"
}

output "base_url" {
  value = "${aws_api_gateway_deployment.deploy.invoke_url}${aws_api_gateway_stage.prod_stage.stage_name}/photos"
}
```

### Notes:
- `upload_lambda.zip` and `random_lambda.zip` should contain the respective Lambda function code.
- The `cors_rule` on S3 allows any origin to upload and download images. Adjust policies according to your security requirements.
- The Lambda functions `upload.handler` and `random.handler` are placeholders; ensure these point to the correct handler functions within your code.
- The `output` provides the base URL for invoking the API Gateway.

