  region = "us-east-1" # or your preferred region
}

resource "aws_key_pair" "my_key_pair" {
  key_name   = "my-key-pair"
  public_key = file("./key.pub")
}

resource "aws_instance" "my_instance" {
  ami                         = "ami-0ff8a91507f77f867" # Replace with recent Amazon Linux AMI ID
  instance_type               = "t2.micro"
  key_name                    = aws_key_pair.my_key_pair.key_name

  tags = {
    Name = "TestInstance"
  }
}

resource "aws_backup_vault" "my_backup_vault" {
  name = "my-backup-vault"
}

resource "aws_backup_plan" "my_backup_plan" {
  name = "my-backup-plan"

  rule {
    rule_name         = "daily-backup"
    target_vault_name = aws_backup_vault.my_backup_vault.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7
    }

    advanced_backup_setting {
      resource_type = "EC2"
    }
  }
}

resource "aws_backup_selection" "my_backup_selection" {
  iam_role_arn = aws_iam_role.my_backup_role.arn
  name         = "my-backup-selection"
  plan_id      = aws_backup_plan.my_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Name"
    value = "TestInstance"
  }
}

resource "aws_iam_role" "my_backup_role" {
  name = "my-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "my_backup_policy_attachment" {
  role       = aws_iam_role.my_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_ami" "amzn-linux-2023-ami" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["al2023-ami-2023.*-x86_64"]
  }
}

resource "aws_key_pair" "cloud_desktop" {
  public_key = file("./supplement/key.pub")
}

resource "aws_instance" "cloud_desktop" {
  ami           = data.aws_ami.amzn-linux-2023-ami.id
  instance_type = "t2.micro"
  key_name      = aws_key_pair.cloud_desktop.key_name
}

resource "aws_backup_plan" "cloud_desktop_backup" {
  name = "cloud_desktop_backup_plan"
  rule {
    rule_name         = "cloud_desktop_backup_rule"
    target_vault_name = aws_backup_vault.valut.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7
    }
  }

  advanced_backup_setting {
    backup_options = {
      WindowsVSS = "enabled"
    }
    resource_type = "EC2"
  }
}

resource "aws_backup_vault" "valut" {
  name = "cloud_desktop_backup_valut"
}

resource "aws_backup_selection" "backup_ec2" {
  iam_role_arn = aws_iam_role.backup.arn

  name    = "backup_ec2"
  plan_id = aws_backup_plan.cloud_desktop_backup.id

  resources = [
    aws_instance.cloud_desktop.arn,
  ]
}

data "aws_iam_policy_document" "backup_assume_role" {
  statement {
    effect = "Allow"

    principals {
      type        = "Service"
      identifiers = ["backup.amazonaws.com"]
    }

    actions = ["sts:AssumeRole"]
  }
}

resource "aws_iam_role" "backup" {
  name               = "backup"
  assume_role_policy = data.aws_iam_policy_document.backup_assume_role.json
}

resource "aws_iam_role_policy_attachment" "backup" {
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
  role       = aws_iam_role.backup.name
}

response:
To create the desired infrastructure using Terraform, we'll go through the steps required to fulfill the request:

1. Define an AWS EC2 key pair using a `public_key` from a file.
2. Launch an AWS EC2 instance using the Amazon Linux 2023 x86_64 AMI with `t2.micro` instance type, and associate it with the defined key pair.
3. Create an AWS Backup vault.
4. Create an AWS Backup plan with a rule scheduled daily at midnight, specifying a lifecycle policy to delete backups after 7 days.
5. Define an `advanced_backup_setting` for the EC2 instance resource.
6. Create a backup selection for the instance linked to the backup plan.
7. Create an IAM role with a specified policy for AWS Backup.

Here's the Terraform HCL configuration implementing these steps:

```hcl
provider "aws" {
  region = "us-east-1" # or your preferred region
}

resource "aws_key_pair" "my_key_pair" {
  key_name   = "my-key-pair"
  public_key = file("./key.pub")
}

resource "aws_instance" "my_instance" {
  ami                         = "ami-0ff8a91507f77f867" # Replace with recent Amazon Linux AMI ID
  instance_type               = "t2.micro"
  key_name                    = aws_key_pair.my_key_pair.key_name

  tags = {
    Name = "TestInstance"
  }
}

resource "aws_backup_vault" "my_backup_vault" {
  name = "my-backup-vault"
}

resource "aws_backup_plan" "my_backup_plan" {
  name = "my-backup-plan"

  rule {
    rule_name         = "daily-backup"
    target_vault_name = aws_backup_vault.my_backup_vault.name
    schedule          = "cron(0 0 * * ? *)"

    lifecycle {
      delete_after = 7
    }

    advanced_backup_setting {
      resource_type = "EC2"
    }
  }
}

resource "aws_backup_selection" "my_backup_selection" {
  iam_role_arn = aws_iam_role.my_backup_role.arn
  name         = "my-backup-selection"
  plan_id      = aws_backup_plan.my_backup_plan.id

  selection_tag {
    type  = "STRINGEQUALS"
    key   = "Name"
    value = "TestInstance"
  }
}

resource "aws_iam_role" "my_backup_role" {
  name = "my-backup-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "backup.amazonaws.com"
        }
      },
    ]
  })
}

resource "aws_iam_role_policy_attachment" "my_backup_policy_attachment" {
  role       = aws_iam_role.my_backup_role.name
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSBackupServiceRolePolicyForBackup"
}
```

**Note:**
- Replace `"ami-0ff8a91507f77f867"` with the actual Amazon Linux 2023 AMI ID for your region.
- Ensure your AWS provider is configured with the correct region and credentials.
- Adjust the instance `ami` dynamically using data source if needed.

