provider "aws" {
  region = "us-east-1"  # Change as needed to the preferred region
}

resource "aws_s3_bucket" "video_bucket" {
  bucket = "my-globally-distributed-streaming-platform"
  acl    = "private"

  versioning {
    enabled = true
  }

  logging {
    target_bucket = aws_s3_bucket.video_bucket.id
    target_prefix = "log/"
  }
}

resource "aws_cloudfront_distribution" "video_distribution" {
  origin {
    domain_name = aws_s3_bucket.video_bucket.bucket_regional_domain_name
    origin_id   = "S3-${aws_s3_bucket.video_bucket.id}"

    s3_origin_config {
      origin_access_identity = aws_cloudfront_origin_access_identity.video_origin.id
    }
  }

  enabled = true

  default_cache_behavior {
    target_origin_id = "S3-${aws_s3_bucket.video_bucket.id}"
    viewer_protocol_policy = "redirect-to-https"
    compress        = true
    cached_methods = ["GET", "HEAD"]
  }

  origin_access_identity {
    comment = "Terraform-managed S3 origin access"
  }

  aliases {
    quantity = 0  # No CNAME
  }
}

resource "aws_cloudfront_origin_access_identity" "video_origin" {
  comment = "Terraform-managed origin access"
}

resource "aws_iam_policy" "cloudfront_policy" {
  name = "my-cloudfront-policy"

  policy = jsonencode({
    Version     = "2012-10-17"
    Statement   = [
      {
        Effect    = "Allow"
        Principal = {
          CloudFront = "true"
        }
        Action     = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_bucket.arn}/*"
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "cloudfront_policy_attachment" {
  role       = "cloudfront-origin-access-role"  # The CloudFront origin access identity uses the AWS managed policy
  policy_arn = aws_iam_policy.cloudfront_policy.arn
}

resource "aws_s3_bucket_policy" "video_bucket_policy" {
  bucket = aws_s3_bucket.video_bucket.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action   = "s3:GetObject", 
        Effect   = "Allow",
        Principal = {
          AWS = "arn:aws:iam::cloudfront:user/CloudFront Origin Access Identity ${aws_cloudfront_origin_access_identity.video_origin.id}"
        },
        Resource = "*",
        Condition = {
          Test  = "StringEquals",
          Variable = "AWS:SourceArn", 
          Values = ["${aws_s3_bucket.video_bucket. .bucket_region_domain_name}"]
        }
      }
    ]
  })
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

resource "aws_s3_bucket" "video_content" {
  bucket_prefix = "video-content-"
}

resource "aws_s3_object" "put_website" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "index.html"
  source = "./supplement/index.html"
  content_type = "text/html"
}

resource "aws_s3_object" "put_website_css" {
  bucket = aws_s3_bucket.video_content.bucket
  key = "css/style.css"
  source = "./supplement/css/style.css"
  content_type = "text/css"
}

resource "aws_s3_bucket_policy" "bucket_policy" {
  bucket = aws_s3_bucket.video_content.id

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Principal = {
          Service = "cloudfront.amazonaws.com"
        }
        Action = "s3:GetObject"
        Resource = "${aws_s3_bucket.video_content.arn}/*"
        Condition = {
          StringEquals = {
            "AWS:SourceArn" = aws_cloudfront_distribution.my_distribution.arn
          }
        }
      }
    ]
  })
}


locals {
  s3_origin_id = "s3_video_content_origin"
}

resource "aws_cloudfront_origin_access_control" "s3_oac" {
  name                              = "s3-oac"
  description                       = "aws access control policy"
  origin_access_control_origin_type = "s3"
  signing_behavior                  = "always"
  signing_protocol                  = "sigv4"
}

resource "aws_cloudfront_distribution" "my_distribution" {
  origin {
    domain_name              = aws_s3_bucket.video_content.bucket_regional_domain_name
    origin_access_control_id = aws_cloudfront_origin_access_control.s3_oac.id
    origin_id                = local.s3_origin_id
  }

  enabled             = true
  default_root_object = "index.html"

  default_cache_behavior {
    allowed_methods  = ["GET", "HEAD"]
    cached_methods   = ["GET", "HEAD"]
    target_origin_id = local.s3_origin_id

    forwarded_values {
