reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_launch_configuration" "launch-config" {
  name_prefix     = "aws-asg-launch-config-"
  image_id        = data.aws_ami.ubuntu.id
  instance_type   = "t2.micro"
  # user_data       = file("user-data.sh")  # load your script if needed
  security_groups = [aws_security_group.instance-sg.id]

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_autoscaling_group" "asg" {
  name                 = "asg"
  min_size             = 1
  max_size             = 3
  desired_capacity     = 1
  launch_configuration = aws_launch_configuration.launch-config.name
  vpc_zone_identifier  = module.vpc.public_subnets

  lifecycle { 
    ignore_changes = [desired_capacity, target_group_arns]
  }

  health_check_type    = "ELB"
}

resource "aws_autoscaling_policy" "scale-down" {
  name                   = "scale-down"
  autoscaling_group_name = aws_autoscaling_group.asg.name
  adjustment_type        = "ChangeInCapacity"
  scaling_adjustment     = -1
  cooldown               = 120
}

resource "aws_cloudwatch_metric_alarm" "scale-down" {
  alarm_description   = "Monitors CPU utilization for Terramino ASG"
  alarm_actions       = [aws_autoscaling_policy.scale-down.arn]
  alarm_name          = "scale-down"
  comparison_operator = "LessThanOrEqualToThreshold"
  namespace           = "AWS/EC2"
  metric_name         = "CPUUtilization"
  threshold           = "10"
  evaluation_periods  = "2"
  period              = "120"
  statistic           = "Average"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.asg.name
  }
}

resource "aws_autoscaling_policy" "scale-up" {
  name                   = "scale-up"
  autoscaling_group_name = aws_autoscaling_group.asg.name
  adjustment_type        = "ChangeInCapacity"
  scaling_adjustment     = 1
  cooldown               = 120
}

resource "aws_cloudwatch_metric_alarm" "scale-up" {
  alarm_description   = "Monitors CPU utilization for Terramino ASG"
  alarm_actions       = [aws_autoscaling_policy.scale-up.arn]
  alarm_name          = "scale-up"
  comparison_operator = "GreaterThanOrEqualToThreshold"
  namespace           = "AWS/EC2"
  metric_name         = "CPUUtilization"
  threshold           = "80"
  evaluation_periods  = "2"
  period              = "120"
  statistic           = "Average"

  dimensions = {
    AutoScalingGroupName = aws_autoscaling_group.asg.name
  }
}

resource "aws_lb" "lb" {
  name               = "my-lb"
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb-sg.id]
  subnets            = module.vpc.public_subnets
}

resource "aws_lb_listener" "lb-listener" {
  load_balancer_arn = aws_lb.lb.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target-group.arn
  }
}

resource "aws_lb_target_group" "target-group" {
  name     = "my-lb-target-group"
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_autoscaling_attachment" "as-attachment" {
  autoscaling_group_name = aws_autoscaling_group.asg.id
  lb_target_group_arn   = aws_lb_target_group.target-group.arn
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

output "lb_endpoint" {
  value = "http://${aws_lb.lb.dns_name}"
}

output "application_endpoint" {
  value = "http://${aws_lb.lb.dns_name}/index.php"
}

output "asg_name" {
  value = aws_autoscaling_group.asg.name
}

response:
To set up a multi-server architecture for a video streaming platform on AWS using Elastic Load Balancing, we need to outline the key components involved in such an architecture. This typically includes managed services for video streaming, compute instances, load balancers, and potentially storage solutions.

### Step-by-Step Configuration:

1. **Elastic Beanstalk Application**: This service can host the video streaming platform's backend servers. Elastic Beanstalk simplifies server setup, capacity provisioning, and management.

2. **Elastic Load Balancer (ELB)**: Distribute incoming traffic across the Backend servers. ELB can help ensure high availability and fault tolerance.

3. **VPC and Subnets**: Define a virtual private cloud and appropriate public/private subnets to organize resources and access.

4. **Security Groups**: Manage ingress and egress for instances within the VPC.

5. **S3 Bucket for Video Storage**: AWS S3 can be used for storing and retrieving video content in a scalable way.

6. **Deployments**: Setup deployments using CloudFormation or the Terraform `aws.elasticbeanstalk` module.

Now, integrating these into Terraform infrastructure code, we can write the configuration as follows:

### HCL Code Block:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_elastic_load_balancer" "video_streaming_elb" {
  name               = "video-streaming-elb"
  subnets            = [aws_vpc.main.id]
  security_groups     = [aws_security_group.elb.id]
}

resource "aws_security_group" "elb" {
  name = "elb-sg"

  ingress {
    from_port   = 80
    to_port     = 80
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  ingress {
    from_port   = 443
    to_port     = 443
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol   = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_elastic_beanstalk_environment" "video_streaming_backend" {
  name                = "Elastic Beanstalk Video Streaming Backend"
  solution            = "64bit Amazon Linux 2 v3.1.2 running Node.js"
  tier                = "WebServer"
  application         = aws_elastic_beanstalk_application.video_streaming_app.id
  instance_type       = "t2.micro"
  min Instances       = 1
  max Instances       = 3
  load_balancer      = aws_elastic_load_balancer.video_streaming_elb.name
  key                = var.eb_key
}

resource "aws_elastic_beanstalk_application" "video_streaming_app" {
  name        = "video-streaming-app"
  description = "Video Streaming application"
  source_bundle {
    url = "https://example.com/my-video-streaming-app-bundle.zip"
  }
}

resource "aws_s3_bucket" "video_content_storage" {
  bucket = "video-streaming-content-bucket"
  acl    = "private"
}

resource "aws_s3_bucket_object" "video_content_object" {
  bucket        = aws_s3_bucket.video_content_storage.id
  key          = "path/to/video/content"
  source       = "path/to/local/video/content"
  acl          = "private"
}

variable "eb_key" {
  description = "The Elastic Beanstalk key to use"
  type        = string
}

output "video_streaming_elb_dns_name" {
  value = aws_elastic_load_balancer.video_streaming_elb.dns_name
}
```

### Explanation:

- **VPC**: Represents the Virtual Private Cloud ensuring isolation of the network.
- **Elastic Load Balancer**: Balances traffic across multiple instances in the backend architecture with security group rules.
- **Elastic Beanstalk**: Automatically handles deployment and scaling of the application.
- **S3 Bucket**: Provides video content storage.
- **Variable Declaration & Output**: Storing configuration variables and outputs for clarity and reuse.

This code is designed to establish foundational components for a typical video streaming platform, organized to maintain scalability, security, and accessibility using AWS Elastic Load Balancing and the Elastic Beanstalk platform. Adjust specific instance types, resource URIs, and details for actual implementation.

