To fulfill your request and generate the Terraform configuration using HCL, we will break down the requirements step-by-step and then provide the combined configuration in a single HCL code block.

1. **AWS VPC Creation:** 
   - Define the VPC with the specified CIDR block.

2. **Subnets with VPC:**
   - Create three subnets associated with the VPC, each with a distinct CIDR block.

3. **Security Group:**
   - Add an ingress rule allowing TCP traffic from the VPC CIDR range to port 80.
   - Add an egress rule permitting TCP traffic from port 80 to any IP address.

4. **Application Load Balancer:**
   - Create an ALB using the application_load_balancer_type, referencing the VPC's security group and the subnets.

5. **Target Group and Listener:**
   - Define a target group with port 80 and HTTP protocol.
   - Add a listener to the ALB forwarding traffic to the target group and acting on HTTP protocol at port 80.

6. **EC2 Instance Registration:**
   - Create a security group and define a registration of an EC2 instance with the target group. Ensure the instance is using the latest Ubuntu AMI.

7. **Route53 Hosted Zone and Alias Records:**
   - Create a hosted zone for "test-video-stream.com".
   - Add two alias records for "lb.test-video-stream.com", pointing to the load balancer's DNS name.

Here is the Terraform HCL code for these configurations:

```hcl
provider "aws" {
  region = "us-east-1"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet1" {
  vpc_id     = aws_vpc.main.id
  cidr_block  = "10.0.4.0/24"
  availability_zone = "us-east-1a"
}

resource "aws_subnet" "subnet2" {
  vpc_id     = aws_vpc.main.id
  cidr_block  = "10.0.5.0/24"
  availability_zone = "us-east-1b"
}

resource "aws_subnet" "subnet3" {
  vpc_id     = aws_vpc.main.id
  cidr_block  = "10.0.6.0/24"
  availability_zone = "us-east-1c"
}

resource "aws_security_group" "alb_sg" {
  name   = "alb_sg"
  vpc_id = aws_vpc.main.id

  ingress {
    description     = "Allow VPC to ALB"
    from_port       = 80
    to_port         = 80
    protocol       = "tcp"
    cidr_blocks    = [aws_vpc.main.cidr_block]
  }

  egress {
    description     = "Allow ALB to reach Internet"
    from_port       = 80
    to_port         = 80
    protocol       = "tcp"
    cidr_blocks    = ["0.0.0.0/0"]
  }
}

resource "aws_lb" "alb" {
  name               = "alb"
  internal           = false
  load_balancer_type = "application"
  subnets            = [aws_subnet.subnet1.id, aws_subnet.subnet2.id, aws_subnet.subnet3.id]
  security_groups    = [aws_security_group.alb_sg.id]
}

resource "aws_lb_target_group" "tg" {
  name      = "tg"
  port      = 80
  protocol  = "HTTP"
  vpc_id    = aws_vpc.main.id

  Health_check {
    protocol = "HTTP"
    matcher  = "200"
    port     = "traffic-port"
  }
}

resource "aws_lb_listener" "front_end" {
  load_balancer_arn = aws_lb.alb.arn
  port              = "80"
  protocol         = "HTTP"

  default_action {
    type         = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
    }
}

resource "aws_instance" "lb_target_instance" {
  ami           = data.aws_ami.latest_ubuntu.id
  instance_type     = "t2.micro"
  subnet_id    = aws_subnet.subnet1.id
  vpc_security_group_ids = [aws_security_group.alb_sg.id]
}

data "aws_ami" "latest_ubuntu" {
  most_recent = true
  filter {
    name   = "name"
    values = ["ubuntu/images/hvm-ssd/ubuntu-bionic-18.04-amd64-server-*"]
  }
  owners = ["469860151204"] // Replace with appropriate owner ID
}

resource "aws_route53_zone" "zon" {
  name    = "test-video-stream.com."
}

resource "aws_route53_record" "record_v4" {
  zone_id         = aws_route53_zone.zon.zone_id
  name            = "lb.test-video-stream.com"
  type            = "A"
  ttl            = "300"
  records = [{
    value = aws_lb.alb.dns_name
  }]
  private_zone = true
}

resource "aws_route53_record" "record_v6" {
  zone_id         = aws_route53_zone.zon.zone_id
  name            = "lb.test-video-stream.com"
  type            = "AAAA"
  ttl            = "300"
  records = [{
    value = aws_lb.alb.dns_name
  }]
  private_zone = true
  evaluate_target_health = true

  allow_overwrite = true
}
```

Make sure to adjust certain inputs (like eigen values and AMI details) as per your existing environment and needs before applying this configuration.

