extracted_code:
provider "aws" {
  region = "us-west-2"
}

# Step 1: Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

# Create Subnets
resource "aws_subnet" "public1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "public-subnet-2"
  }
}

# Step 2: Create a DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.public1.id, aws_subnet.public2.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Step 3: Create a Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust to meet your security requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 4: Create a KMS Key for RDS Encryption
resource "aws_kms_key" "rds_key" {
  description = "KMS key for RDS encryption"
}

# Step 5: Create a Custom PostgreSQL Parameter Group
resource "aws_rds_cluster_parameter_group" "custom_pg" {
  name        = "custom-postgres-parameter-group"
  family      = "aurora-postgresql10" # Update the family based on the PostgreSQL version
  description = "Custom PostgreSQL parameter group"

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

# Step 6: Create the RDS instance with configured parameters
resource "aws_db_instance" "postgres_rds" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "postgres"
  engine_version       = "10.7"
  instance_class       = "db.t3.micro"
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  multi_az              = true
  kms_key_id            = aws_kms_key.rds_key.arn
  backup_retention_period = 7

  # Use the custom parameter group
  parameter_group_name = aws_rds_cluster_parameter_group.custom_pg.name

  tags = {
