terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

resource "aws_db_subnet_group" "db-subnet-group" {
  name       = "db-subnet-group"
  subnet_ids = module.vpc.public_subnets
}

resource "aws_security_group" "db-sg" {
  name = "db-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-sg-ingress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-sg-egress-rule" {
  from_port       = 5432
  to_port         = 5432
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.db-sg.id
}

resource "aws_db_parameter_group" "postgre-param-group" {
  name   = "pgparamgrp15"
  family = "postgres15"

  parameter {
    name  = "password_encryption"
    value = "scram-sha-256"
  }

  parameter {
    name  = "rds.force_ssl"
    value = "0"
  }

  lifecycle {
    create_before_destroy = true
  }
}

resource "aws_kms_key" "rds-key" {
  description             = "kmsrds"
  deletion_window_in_days = 14
}

resource "aws_db_instance" "postgres" {
  identifier                      = "pg"
  skip_final_snapshot             = true
  allocated_storage               = 5
  backup_retention_period         = 7
  db_subnet_group_name            = aws_db_subnet_group.db-subnet-group.id
  parameter_group_name            = aws_db_parameter_group.postgre-param-group.name
  enabled_cloudwatch_logs_exports = ["postgresql", "upgrade"]
  engine                          = "postgres"
  engine_version                  = "15"
  instance_class                  = "db.t3.micro"
  db_name                         = "postgres" # Initial database name
  username                        = "myusername"
  password                        = "mypassword"
  vpc_security_group_ids          = [aws_security_group.db-sg.id]
  # Other security settings
  publicly_accessible             = true
  multi_az                        = true
  storage_encrypted               = true
  kms_key_id                      = aws_kms_key.rds-key.arn
  # Default daily backup window
  # https://docs.aws.amazon.com/AmazonRDS/latest/UserGuide/USER_WorkingWithAutomatedBackups.html#USER_WorkingWithAutomatedBackups.BackupWindow
}

response:
To address your request, we will break it down into the following components:

1. **Create a VPC**: This will provide an isolated network for your RDS instance.
2. **Create subnets and a DB subnet group**: Distribute RDS instances across multiple Availability Zones for high availability.
3. **Create a security group**: To control access to the RDS instance.
4. **Create a KMS key**: For encrypting your RDS instance.
5. **Create a custom parameter group**: To configure specific settings for the PostgreSQL instance.
6. **Create the RDS instance**: With specified configurations like Multi-AZ, engine version, and storage requirements.

Here's the Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-west-2"
}

# Step 1: Create a VPC
resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

# Create Internet Gateway
resource "aws_internet_gateway" "main" {
  vpc_id = aws_vpc.main.id
}

# Create Subnets
resource "aws_subnet" "public1" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "public-subnet-1"
  }
}

resource "aws_subnet" "public2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"

  tags = {
    Name = "public-subnet-2"
  }
}

# Step 2: Create a DB Subnet Group
resource "aws_db_subnet_group" "main" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.public1.id, aws_subnet.public2.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

# Step 3: Create a Security Group for RDS
resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Security group for PostgreSQL RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    description = "PostgreSQL"
    from_port   = 5432
    to_port     = 5432
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"] # Adjust to meet your security requirements
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

# Step 4: Create a KMS Key for RDS Encryption
resource "aws_kms_key" "rds_key" {
  description = "KMS key for RDS encryption"
}

# Step 5: Create a Custom PostgreSQL Parameter Group
resource "aws_rds_cluster_parameter_group" "custom_pg" {
  name        = "custom-postgres-parameter-group"
  family      = "aurora-postgresql10" # Update the family based on the PostgreSQL version
  description = "Custom PostgreSQL parameter group"

  parameter {
    name  = "max_connections"
    value = "100"
  }
}

# Step 6: Create the RDS instance with configured parameters
resource "aws_db_instance" "postgres_rds" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "postgres"
  engine_version       = "10.7"
  instance_class       = "db.t3.micro"
  db_subnet_group_name = aws_db_subnet_group.main.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
  multi_az              = true
  kms_key_id            = aws_kms_key.rds_key.arn
  backup_retention_period = 7

  # Use the custom parameter group
  parameter_group_name = aws_rds_cluster_parameter_group.custom_pg.name

  tags = {
    Name = "my-postgres-rds"
  }
}
```

### Additional Notes:
- **Region**: Adjust the region (`us-west-2`) as necessary for your use case.
- **Subnets**: Instances are placed in two subnets across different AZs for high availability.
- **Security Group**: The ingress rule allows access from anywhere; modify `cidr_blocks` as needed to enhance security.
- **KMS Key**: Used for encryption at rest.
- **Parameter Group**: Modify parameters like `max_connections` according to your specific requirements.
- **Engine Version**: Ensure it matches your PostgreSQL version needs. 

This configuration is a starting point, and you may want to adjust CIDR blocks, security policies, or resource allocation based on best practices and organization policies.

