  vpc_id     = aws_vpc.primary_vpc.id
  availability_zone = data.aws_availability_zones.available.names[0]
  cidr_block = "10.0.1.0/24"

  tags = {
    "Name" = "public-subnet-1"
  }
}

resource "aws_subnet" "public_subnet_2" {
  vpc_id     = aws_vpc.primary_vpc.id
  availability_zone = data.aws_availability_zones.available.names[1]
  cidr_block = "10.0.2.0/24"

  tags = {
    "Name" = "public-subnet-2"
  }
}

resource "aws_security_group" "rds_security_group" {
  vpc_id = aws_vpc.primary_vpc.id
  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol   = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }
  tags = {
    Name = "rds-security-group"
  }
}

resource "aws_db_instance" "mysql_rds_instance" {
  identifier           = "mysql-rds"
  engine              = "mysql"
  engine_version      = "5.7"
  instance_class      = "db.m5.large"
  allocated_storage   = 500
  storage_type        = "gp2"
  backup_retention_period = 7
  vpc_security_group_ids = [aws_security_group.rds_security_group.id]
  db_subnet_group_name = aws_db_subnet_group.primary_db_subnet_group.name
  publicly_accessible = true
  skip_final_snapshot = true
  # Additional configurations like username, password, etc. are needed
}

resource "aws_db_subnet_group" "primary_db_subnet_group" {
  subnet_ids = [aws_subnet.public_subnet_1.id, aws_subnet.public_subnet_2.id]
  name        = "mydbsubnetgroup"

  db_subnet_group_name = aws_db_subnet_group.primary_db_subnet_group.name
}

resource "aws_route53_record" "mysql_endpoint" {
  zone_id = data.aws_route53_zone.example_zone.zone_id
  name    = "mysql.example.com"
  type    = "CNAME"
  ttl     = "300"
  records {
    value = "${aws_db_instance.mysql_rds_instance.address}"
  }
