  secret_id          = aws_secretsmanager_secret.rds_secret.id
}

resource "aws_secretsmanager_secret" "example_db_password" {
  name   = "my-db-password"
  description = "MySQL database password"
}

resource "aws_secretsmanager_secret_version" "exampledbpassword" {
  secret_id       = aws_secretsmanager_secret.example_db_password.id
  secret_string   = var.password_value
}

resource "aws_db_subnet_group" "example_db_subnet_group" {
  name       = "example-subnet-group"
  db_subnets  = [aws_subnet.example_subnet.id]
}

output "example_output" {
  value = {
    cluster_id = aws_rds_cluster_instance.example_instance.name
    instance_security_group = aws_rds_cluster_instance.example_instance.security_groups[0]
  }
  description = "Aurora RDS Cluster Configuration"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name                 = "main-vpc"
  cidr                 = "10.0.0.0/16"
  azs                  = data.aws_availability_zones.available.names
  private_subnets      = ["10.0.1.0/24", "10.0.2.0/24"]
  public_subnets       = ["10.0.3.0/24", "10.0.4.0/24"]
}

resource "aws_security_group" "rds-proxy-sg" {
  name        = "rds-proxy-sg"
  vpc_id      = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "db-proxy-sg-ingress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_vpc_security_group_egress_rule" "db-proxy-sg-egress-rule" {
  from_port       = 3306
  to_port         = 3306
  ip_protocol     = "tcp"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.rds-proxy-sg.id
}

resource "aws_db_subnet_group" "main" {
  name       = "main"
  subnet_ids = module.vpc.private_subnets
}

resource "aws_rds_cluster" "example" {
  cluster_identifier      = "example-cluster"
  engine                  = "aurora-mysql"
  engine_version          = "8.0.mysql_aurora.3.08.0"
  master_username         = "myusername"
  master_password         = "password123"
  database_name           = "exampledb"
  backup_retention_period = 5
  preferred_backup_window = "07:00-09:00"
  skip_final_snapshot     = true
  vpc_security_group_ids  = [aws_security_group.rds-proxy-sg.id]
  db_subnet_group_name    = aws_db_subnet_group.main.name
}

resource "aws_secretsmanager_secret" "db-credentials" {
  name_prefix = "db-credentials-"
}

resource "aws_secretsmanager_secret_version" "db-credentials-version" {
  secret_id     = aws_secretsmanager_secret.db-credentials.id
  secret_string = jsonencode({
    username = aws_rds_cluster.example.master_username
    password = aws_rds_cluster.example.master_password
  })
}

resource "aws_iam_role" "rds-proxy-role" {
  name = "rds-proxy-role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "rds.amazonaws.com"
        }
      }
    ]
  })
}

resource "aws_iam_policy" "rds-proxy-policy" {
  name        = "rds-proxy-policy"

  policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Effect = "Allow"
        Action = [
          "secretsmanager:GetSecretValue",
        ]
        Resource = [
          "${aws_secretsmanager_secret_version.db-credentials-version.arn}",
        ]
      }
    ]
  })
}

resource "aws_iam_role_policy_attachment" "attach-proxy-policy" {
  role       = aws_iam_role.rds-proxy-role.name
  policy_arn = aws_iam_policy.rds-proxy-policy.arn
}

resource "aws_db_proxy" "example" {
  name                   = "example-proxy"
  debug_logging          = false
  engine_family          = "MYSQL"
  idle_client_timeout    = 1800
  require_tls            = true
  role_arn               = aws_iam_role.rds-proxy-role.arn
  vpc_security_group_ids = [aws_security_group.rds-proxy-sg.id]
  vpc_subnet_ids         = module.vpc.private_subnets

  auth {
    auth_scheme  = "SECRETS"
    secret_arn   = aws_secretsmanager_secret.db-credentials.arn
    iam_auth     = "DISABLED"
  }
}

resource "aws_db_proxy_default_target_group" "example" {
  db_proxy_name = aws_db_proxy.example.name

  connection_pool_config {
    connection_borrow_timeout    = 120
    init_query                   = "SET x=1, y=2"
    max_connections_percent      = 100
    max_idle_connections_percent = 50
    session_pinning_filters      = ["EXCLUDE_VARIABLE_SETS"]
  }
}

resource "aws_db_proxy_target" "example" {
  db_cluster_identifier = aws_rds_cluster.example.cluster_identifier
  db_proxy_name          = aws_db_proxy.example.name
  target_group_name      = aws_db_proxy_default_target_group.example.name
}

response:
To create an AWS Aurora MySQL RDS deployment with an RDS Proxy, VPC and subnet configuration, security groups, and integration with AWS Secrets Manager for secure credential management, we will follow a systematic approach to generate the Terraform configuration. This configuration will ensure that all components are set up correctly with appropriate security settings and management capabilities.

1. **AWS VPC and Subnet Configuration**: We'll first define the VPC and subnet where the RDS instance will reside.

2. **Security Groups**: The security groups are necessary to set firewall rules for the database.

3. **RDS Instance and Proxy**: We define the RDS instance and the Proxy configuration for improved connection pooling.

4. **AWS Secrets Manager**: This will manage the database credentials securely.

Here's the corresponding Terraform configuration in HCL:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "example_vpc" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "example_subnet" {
  vpc_id            = aws_vpc.example_vpc.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-security-group"
  description = "Allow inbound traffic for RDS instance"
  vpc_id     = aws_vpc.example_vpc.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }
}

resource "aws_db_subnet_group" "example_db_subnet_group" {
  name        = "my-db-subnet-group"
  subnet_ids  = [aws_subnet.example_subnet.id]

  tags = {
    Name = "My DB Subnet Group"
  }
}

resource "aws_secretsmanager_secret" "rds_secret" {
  name = "rdssecret"
}

resource "aws_secretsmanager_secret_version" "rds_secret_version" {
  secret_id     = aws_secretsmanager_secret.rds_secret.id
  secret_string = "{"username":"dbadmin", "password":"securepassword"}"
}

resource "aws_rds_cluster" "example_cluster" {
  cluster_identifier   = "example-cluster"
  database_name        = "mydb"
  master_username      = "dbadmin"
  master_password      = "initialpassword"
  db_subnet_group_name = aws_db_subnet_group.example_db_subnet_group.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]
}

resource "aws_rds_cluster_instance" "example_cluster_instance" {
  identifier         = "example-cluster-instance"
  db_instance_class = "db.t3.micro"
  engine_version    = "5.7.12"
  engine            = "aurora-mysql"

  cluster_identifier = aws_rds_cluster.example_cluster.id
}

resource "aws_rds_cluster_instance" "example_instance" {
  identifier     = "example-instance"
  count         = 1
  engine_version = "5.7.12"
  engine        = "aurora-mysql"
  cluster_identifier  = aws_rds_cluster.example_cluster.id
}

resource "aws_rds_db_instance" "example_rds_db" {
  allocated_storage       = 200
  instance_class          = "db.t2.micro"
  multi_az               = false
  engine                 = "mysql"
  engine_version         = "5.7.12"
  master_username        = "dbadmin"
  master_password        = "initialpassword"
  db_name               = "mydb"
  db_subnet_group_name   = aws_db_subnet_group.example_db_subnet_group.name
  skip_final_snapshot   = true
  publicly_accessible    = true
}

resource "aws_rds_cluster" "example_proxy" {
  identifier              = "example-cluster-proxy"
  cluster_resource_id     = aws_rds_cluster_instance.example_instance.id
}

resource "aws_secretsmanager_secret_migration" "db_credentials_migration" {
  migration_type     = "SECRET"
  secret_id          = aws_secretsmanager_secret.rds_secret.id
}

resource "aws_secretsmanager_secret" "example_db_password" {
  name   = "my-db-password"
  description = "MySQL database password"
}

resource "aws_secretsmanager_secret_version" "exampledbpassword" {
  secret_id       = aws_secretsmanager_secret.example_db_password.id
  secret_string   = var.password_value
}

resource "aws_db_subnet_group" "example_db_subnet_group" {
  name       = "example-subnet-group"
  db_subnets  = [aws_subnet.example_subnet.id]
}

output "example_output" {
  value = {
    cluster_id = aws_rds_cluster_instance.example_instance.name
    instance_security_group = aws_rds_cluster_instance.example_instance.security_groups[0]
  }
  description = "Aurora RDS Cluster Configuration"
}
```

This configuration contains:

- The VPC (`aws_vpc`) and subnet (`aws_subnet`) for your RDS instance.
- Security group (`aws_security_group`) allowing inbound and outbound access for your RDS instance.
- A secret stored in Secrets Manager (`aws_secretsmanager_secret`) for securely storing your RDS credentials.
- An Aurora MySQL cluster (`aws_rds_cluster`) and associated instances (`aws_rds_cluster_instance`).
- An RDS DB instance (`aws_rds_db_instance`) configured with the necessary details.
- Provide a migration strategy for secret management using `aws_secretsmanager_secret_migration`.

Be sure to revise placeholders (e.g., "initialpassword", "privatepassword", etc.), structured values, and adjust any specifics to fit your requirements before implementation.

