provider "aws" {
  region = "us-west-2" # use your desired AWS region
}

# S3 Bucket to store backups
resource "aws_s3_bucket" "backup_bucket" {
  bucket = "my-backup-bucket"
  acl    = "private"

  lifecycle_rule {
    id      = "glacier_rule"
    enabled = true

    transition {
      days          = 30
      storage_class = "GLACIER"
    }

    expiration {
      days = 365
    }
  }
}

# AWS Data Lifecycle Manager policy for the S3 bucket
resource "aws_dlm_lifecycle_policy" "glacier_policy" {
  description        = "S3 bucket lifecycle policy for Glacier transition"
  execution_role_arn = aws_iam_role.dlm_role.arn

  policy_details {
    policy_type = "S3"

    schedule {
      name = "Daily"
      create_rule {
        interval = 24
        interval_unit = "HOURS"
      }
      retain_rule {
        count = 7 # Retain daily backups for 7 days
      }

      tags_to_add = {
        "Backup" = "true"
      }
    }

    target_tags = {
      "Backup" = "true"
    }
  }
}

# IAM Role for Data Lifecycle Manager
resource "aws_iam_role" "dlm_role" {
  name = "dlm_role"

  assume_role_policy = jsonencode({
    Version = "2012-10-17"
    Statement = [
      {
        Action = "sts:AssumeRole"
        Effect = "Allow"
        Principal = {
          Service = "dlm.amazonaws.com"
        }
      }
    ]
  })
}

# Attach the necessary policy to the DLM role
resource "aws_iam_policy_attachment" "dlm_policy_attachment" {
  name       = "dlm_policy_attachment"
  roles      = [aws_iam_role.dlm_role.name]
  policy_arn = "arn:aws:iam::aws:policy/service-role/AWSDataLifecycleManagerDefaultPolicy"
}

# Glacier Vault (optional, only if you need to directly interact with Glacier API through vaults)
resource "aws_glacier_vault" "example_vault" {
  name = "example-vault"
  region = "us-west-2"
}

