  role   = aws_iam_role.s3_notification_role.name
}

# Resource: S3 Bucket with Glacier Storage Class
resource "aws_s3_bucket" "bucket" {
  bucket = "my-glacier-bucket"
  acl    = "private"
  versioning {
    enabled = true
  }

  server_side_encryption_configuration {
    rule {
    apply_server_side_encryption_by_default {
      sse_algorithm = "AES256"
    }
  }
  }
  lifecycle_rule {
    id   = "archive-to-glacier"
    enabled = true

    transitions {
      transition {
        storage_class = "GLACIER"
        expiration {
          days = 30
        }
      }
    }
  }
  # Notify an SNS Topic (or Lambda) on objects lifecycle transition (e.g., move to Glacier storage)
  notification {
    configuration = {
      event_bridge = {
        event_type = "archive-transition"
        prefix     = "access_plus_1"
        suffix     = "s3."
        destination = {
          sns_topic_arn = "arn:aws:sns:us-west-2:123456789012:my-topic"
        }
      }
    }
  }
}

