To create a Terraform configuration for AWS that provisions a Network Load Balancer linked to a t2.micro EC2 instance, we will follow these steps:

1. **Define AWS Provider:**
   - Set up the AWS provider to manage resources on AWS.

2. **Create AWS VPC and Subnets:**
   - Create a Virtual Private Cloud (VPC) and a subnet to host the network load balancer and EC2 instances.

3. **Security Group:**
   - Define a security group for the EC2 instance to allow traffic through the load balancer.

4. **Launch EC2 Instance:**
   - Provision a t2.micro EC2 instance within the VPC.

5. **Create Network Load Balancer:**
   - Set up the network load balancer, target group, and listener to link with the EC2 instance.

Here is the complete Terraform configuration in HCL format:

```hcl
provider "aws" {
  region = "us-east-1" # Set your desired region
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "subnet" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-east-1a" # Choose your availability zone
}

resource "aws_instance" "example" {
  ami                    = "ami-0c55b159cbfafe1fe" # Replace with your desired AMI ID
  instance_type         = "t2.micro"
  vpc_security_group_ids = [aws_security_group.example.id]
  subnet_id             = aws_subnet.subnet.id
}

resource "aws_security_group" "example" {
  vpc_id = aws_vpc.main.id

  ingress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    security_group_id = aws_security_group.example.id
  }

  egress {
    from_port = 0
    to_port   = 0
    protocol  = "-1"
  }
}

resource "aws_lb_target_group" "tg" {
  name     = "my-target-group"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id

  target_type = "instance"

  health_check {
    protocol = "TCP"
    matcher  = "healthy"
    port     = 80
  }
}

resource "aws_lb" "nlb" {
  name               = "my-network-load-balancer"
  internal           = true
  load_balancer_type = "network"

  enable_cross_zone_load_balancing       = true
  subnet_mapping {
    subnet_id      = aws_subnet.subnet.id
    subnet_mapping = "lb-subnet" # Optionally, map your subnet ID to internal mapping
  }
}

resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = 80
  protocol         = "TCP"
  default_action {
