response:
To provision a Network Load Balancer using Terraform, we need to consider the specific cloud provider, as the implementation details differ between AWS, GCP, and Azure. I'll provide a configuration for each platform.

### AWS Network Load Balancer

For AWS, we'll use an Elastic Load Balancer (ELB) of the type `network`. Here's how you can set it up:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
}

resource "aws_subnet" "public" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.1.0/24"
  availability_zone = "us-west-2a"
}

resource "aws_subnet" "public_2" {
  vpc_id     = aws_vpc.main.id
  cidr_block = "10.0.2.0/24"
  availability_zone = "us-west-2b"
}

resource "aws_lb" "nlb" {
  name               = "nlb-example"
  load_balancer_type = "network"
  subnets            = [aws_subnet.public.id, aws_subnet.public_2.id]
}

resource "aws_lb_target_group" "tg" {
  name     = "nlb-tg"
  port     = 80
  protocol = "TCP"
  vpc_id   = aws_vpc.main.id
}

resource "aws_lb_listener" "listener" {
  load_balancer_arn = aws_lb.nlb.arn
  port              = "80"
  protocol          = "TCP"

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.tg.arn
  }
}
```

### GCP Network Load Balancer

For GCP, here's how you can set up a Network Load Balancer:

```hcl
provider "google" {
  project = "your-gcp-project-id"
  region  = "us-west1"
}

resource "google_compute_network" "vpc_network" {
  name                    = "tf-vpc-network"
  auto_create_subnetworks = false
}

resource "google_compute_global_address" "nlb_ip" {
  name = "nlb-ip"
}

resource "google_compute_url_map" "default" {
  name            = "nlb-url-map"
  default_service = google_compute_target_http_proxy.default.id
}

resource "google_compute_target_http_proxy" "default" {
  name    = "nlb-target-proxy"
  url_map = google_compute_url_map.default.id
}

resource "google_compute_backend_service" "default" {
  name        = "nlb-backend-service"
  protocol    = "TCP"
  port_name   = "http"
  timeout_sec = 10

  health_checks = [google_compute_health_check.default.id]
}

resource "google_compute_http_health_check" "default" {
  name               = "http-basic-check"
  request_path       = "/health"
  check_interval_sec = 1
  timeout_sec        = 1
}

resource "google_compute_forwarding_rule" "default" {
  name       = "nlb-forwarding-rule"
  target     = google_compute_target_http_proxy.default.id
  ip_address = google_compute_global_address.nlb_ip.address
  port_range = "80"
}
```

### Azure Network Load Balancer

For Azure, the configuration is as follows:

```hcl
provider "azurerm" {
  features {}
  location = "West US"
}

resource "azurerm_resource_group" "main" {
  name     = "network-lb-group"
  location = "westus"
}

resource "azurerm_virtual_network" "main" {
  name                = "vnet"
  address_space       = ["10.0.0.0/16"]
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
}

resource "azurerm_subnet" "main" {
  name                 = "subnet1"
  resource_group_name  = azurerm_resource_group.main.name
  virtual_network_name = azurerm_virtual_network.main.name
  address_prefixes     = ["10.0.1.0/24"]
}

resource "azurerm_public_ip" "main" {
  name                = "nlb-pip"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name
  allocation_method   = "Static"
  sku                 = "Standard"
}

resource "azurerm_lb" "main" {
  name                = "nlb"
  location            = azurerm_resource_group.main.location
  resource_group_name = azurerm_resource_group.main.name

  frontend_ip_configuration {
    name                 = "public"
    public_ip_address_id = azurerm_public_ip.main.id
  }
}

resource "azurerm_lb_backend_address_pool" "main" {
  loadbalancer_id = azurerm_lb.main.id
  name            = "backendPool"
}

resource "azurerm_lb_probe" "main" {
  resource_group_name = azurerm_resource_group.main.name
  loadbalancer_id     = azurerm_lb.main.id
  name                = "tcpProbe"
  protocol            = "Tcp"
  port                = 80
}

resource "azurerm_lb_rule" "main" {
  resource_group_name            = azurerm_resource_group.main.name
  loadbalancer_id                = azurerm_lb.main.id
  name                           = "lbRule"
  protocol                       = "Tcp"
  frontend_port                  = 80
  backend_port                   = 80
  frontend_ip_configuration_name = "public"
  backend_address_pool_id        = azurerm_lb_backend_address_pool.main.id
  probe_id                       = azurerm_lb_probe.main.id
}
```

