# AWS Application Load Balancer with HTTP to HTTPS redirect
provider "aws" {
  region = "us-east-1"
}

resource "aws_lb" "example_alb" {
  name = "example-lb"
  internal = false
  load_balancer_type = "application"
}

resource "aws_lb_listener" "http" {
  load_balancer_arn = aws_lb.example_alb.arn
  port = 80
  protocol = "HTTP"

  default_action {
    type = "redirect"
    redirect {
      port    = "443"
      protocol = "HTTPS"
      host = "#{host}"
      path     = "/"
      query    = "#{query}"
      status_code = "HTTP_301"
    }
  }
}

resource "aws_lb_listener" "https" {
  load_balancer_arn = aws_lb.example_alb.arn
  port = 443
  protocol = "HTTPS"
  ssl_policy = "ELBSecurityPolicy-2016-10"
  certificate_arn = aws_acm_certificate.example_acm_certificate.arn
}

resource "aws_acm_certificate" "example_acm_certificate" {
  domain_name = "example.com"
  validation_method = "DNS"
}

# GCP URL Map and HTTP to HTTPS redirect
provider "google" {
  credentials = file("path/to/credentials.json")
  project = "your-gcp-project-id"
  region = "us-central1"
}

resource "google_compute_target_http_proxy" "target_http_proxy" {
  name        = "target-http-proxy"
  project     = "your-gcp-project-id"
  url_map     = google_compute_url_map.url_map.self_link
  content_negotiation = false
}

resource "google_compute_url_map" "url_map" {
  name        = "url-map"
  project     = "your-gcp-project-id"
}

resource "google_compute_global_forwarding_rule" "rule" {
  target        = google_compute_target_http_proxy.target_http_proxy.self_link
  # Assignments here dictate from where to whom traffic should be forwarded or how to behave
}

# Google Cloud HTTP Load Balancer within URL Map to handle HTTPS only
resource "google_compute_target_ssl_proxy" "proxy" {
  name        = "target-ssl-proxy"
  target_ssl_proxy = google_compute_forwarding_rule.self_link
  ssl_certificates = [google_compute_ssl_certificate.example_cert]
}

