  internal           = false
}

resource "aws_security_group" "alb_sg" {
  name   = "alb-sg"
  vpc_id = "vpc-12345678"

  ingress {
    from_port   = 443
    to_port     = 443
    protocol   = "tcp"
    description = "OIDC auth from provider"
  }
}

resource "aws_alb_target_group" "example" {
  name     = "example-target-group"
  target_type = "ip"
  targets = [
    {
      id = "i-1234567890"
      port = 80
    }
  ]
  port     = 80
  protocol = "HTTP"
  vpc_id  = "vpc-12345678"
}

resource "aws_alb_listener" "example" {
  load_balancer_arn = aws_alb.example.arn
  port              = 443
  protocol         = "HTTPS"
  ssl_policy       = "ELBSecurityPolicy-2016-08"
  certificate_arn  = aws_acm_certificate.cert.arn

  default_action {
    type             = "authenticate-oidc"
    order           = 1
    target_group_arn = aws_alb_target_group.example.arn
    on_unauthenticated_request {
      action= "deny"
      certificate_arn = aws_alb_listener.cert.arn
    }
  }
}

resource "aws_acm_certificate" "cert" {
  arn = "arn:aws:acm:region:account-id:certificate/12345678-1234-1234-1234-1234567890"
  mixed_bag_coverage = true
}

resource "aws_cognito_user_pool_client" "example" {
  user_pool_id = "pool_id"
  allowed_oauth_flows = ["code"]
  allowed_oauth_flows_user_pool_client = ["client_id"]
  allowed_oauth_flows = ["implicit"]
  allowed_oauth_scopes = ["openid"]
  generate_secret = true
}

resource "aws_alb_listener" "auth" {
  load_balancer_arn = aws_alb.example.id
  port           = 443
  protocol       = "HTTPS"
  ssl_policy     = "my-SSL-policy"

  default_action {
    type              = "forward"
    target_group_arn = aws_alb_target_group.example.id
    target_group_order = 1
    fallback_action = {
      type                = "fixed-response"
      fixed_response = {
        content_type = "application/json"
        message_body = jsonencode({ "message" = "unauthorized" })
        statusCode  = "401"
      }
    }
  }
}

resource "aws_cognito_identity_pool" "example" {
  allow_unauthenticated_identities = false

  identity_pool_id = "pool_id"
}

reference:
terraform {
  required_providers {
    aws = {
      source  = "hashicorp/aws"
      version = "~> 5.75"
    }
  }

  required_version = "~> 1.9.8"
}

provider "aws" {
  region  = "us-east-1"
  profile = "admin-1"

  assume_role {
    role_arn = "arn:aws:iam::590184057477:role/yicun-iac"
  }
}

data "aws_availability_zones" "available" {
  state = "available"
}

module "vpc" {
  source  = "terraform-aws-modules/vpc/aws"

  name = "main-vpc"
  cidr = "10.0.0.0/16"

  azs                  = data.aws_availability_zones.available.names
  public_subnets       = ["10.0.4.0/24", "10.0.5.0/24", "10.0.6.0/24"]
}

data "aws_ami" "ubuntu" {
  most_recent = true
  owners      = ["amazon"]

  filter {
    name   = "name"
    values = ["*ubuntu-noble-24.04-amd64-server-*"]
  }
}

resource "aws_security_group" "instance-sg" {
  name = "instance-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "instance-sg-ingress-rule" {
  from_port       = 80
  to_port         = 80
  ip_protocol     = "tcp"
  referenced_security_group_id = aws_security_group.lb-sg.id
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_vpc_security_group_egress_rule" "instance-sg-egress-rule" {
  from_port       = 0
  to_port         = 0
  ip_protocol     = "-1"
  cidr_ipv4       = "0.0.0.0/0"
  security_group_id = aws_security_group.instance-sg.id
}

resource "aws_security_group" "lb-sg" {
  name = "lb-sg"
  vpc_id = module.vpc.vpc_id
}

resource "aws_vpc_security_group_ingress_rule" "lb-sg-ingress-rule" {
  from_port   = 80
  to_port     = 80
  ip_protocol = "tcp"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}

resource "aws_vpc_security_group_egress_rule" "lb-sg-egress-rule" {
  from_port   = 0
  to_port     = 0
  ip_protocol = "-1"
  cidr_ipv4   = "0.0.0.0/0"
  security_group_id = aws_security_group.lb-sg.id
}


resource "aws_instance" "my_instance" {
  ami           = data.aws_ami.ubuntu.id
  instance_type = "t2.micro"
  subnet_id     = module.vpc.public_subnets[0]
  security_groups = [ aws_security_group.instance-sg.id ]
}

resource "aws_lb" "test" {
  subnets            = module.vpc.public_subnets
  internal           = false
  load_balancer_type = "application"
  security_groups    = [aws_security_group.lb-sg.id]
}

resource "aws_lb_listener" "my_listener" {
  load_balancer_arn = aws_lb.test.arn
  port              = "80"
  protocol          = "HTTP"

  default_action {
    type = "authenticate-oidc"

  authenticate_oidc {
      authorization_endpoint = "https://example.com/authorization_endpoint"
      client_id              = "client_id"
      client_secret          = "client_secret"
      issuer                 = "https://example.com"
      token_endpoint         = "https://example.com/token_endpoint"
      user_info_endpoint     = "https://example.com/user_info_endpoint"
    }
  }

  default_action {
    type             = "forward"
    target_group_arn = aws_lb_target_group.target_group.arn
  }
}

resource "aws_lb_target_group" "target_group" {
  port     = 80
  protocol = "HTTP"
  vpc_id   = module.vpc.vpc_id
}

resource "aws_lb_target_group_attachment" "ec2_attach" {
  target_group_arn = aws_lb_target_group.target_group.arn
  target_id = aws_instance.my_instance.id
}

