To set up a simple SQL database on AWS using Terraform, we'll perform the following steps:

1. **Configure the AWS Provider**: Ensure Terraform is set up to interact with AWS by specifying a region.
2. **Create a VPC and Subnet**: Set up a VPC and a subnet where your RDS instance will reside.
3. **Create an RDS Instance**: Deploy a MySQL RDS database instance.
4. **Set Up Security Groups**: Define a security group to control access to the RDS instance.

Here's the complete Terraform configuration:

```hcl
provider "aws" {
  region = "us-west-2"
}

resource "aws_vpc" "main" {
  cidr_block = "10.0.0.0/16"
  enable_dns_support   = true
  enable_dns_hostnames = true

  tags = {
    Name = "main-vpc"
  }
}

resource "aws_subnet" "main" {
  vpc_id            = aws_vpc.main.id
  cidr_block        = "10.0.1.0/24"
  availability_zone = "us-west-2a"

  tags = {
    Name = "main-subnet"
  }
}

resource "aws_security_group" "rds_sg" {
  name        = "rds-sg"
  description = "Allow traffic to RDS"
  vpc_id      = aws_vpc.main.id

  ingress {
    from_port   = 3306
    to_port     = 3306
    protocol    = "tcp"
    cidr_blocks = ["0.0.0.0/0"]
  }

  egress {
    from_port   = 0
    to_port     = 0
    protocol    = "-1"
    cidr_blocks = ["0.0.0.0/0"]
  }

  tags = {
    Name = "rds-security-group"
  }
}

resource "aws_db_instance" "mysql_db" {
  allocated_storage    = 20
  storage_type         = "gp2"
  engine               = "mysql"
  engine_version       = "8.0"
  instance_class       = "db.t2.micro"
  name                 = "mydb"
  username             = "user"
  password             = "password123"
  parameter_group_name = "default.mysql8.0"
  db_subnet_group_name = aws_db_subnet_group.db_subnet.name
  vpc_security_group_ids = [aws_security_group.rds_sg.id]

  skip_final_snapshot = true

  tags = {
    Name = "my-mysql-db"
  }
}

resource "aws_db_subnet_group" "db_subnet" {
  name       = "my-db-subnet-group"
  subnet_ids = [aws_subnet.main.id]

  tags = {
    Name = "my-db-subnet-group"
  }
}
```

This setup creates a basic MySQL RDS instance in AWS with a VPC, subnet, security group, and everything required to access the database using port 3306. You should adjust the username, password, and CIDR blocks as needed for production usage.

